/* techniques q09 (113 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q09"]=window.__LIBQ["tien-nghich"]["q09"]||{};window.__LIBQ["tien-nghich"]["q09"]["techniques"]={"updatedAt":"2026-07-17","count":113,"techniques":[{"id":"hac-da-than-thong","name":"Hắc Dạ Thần Thông","cn":"黑夜神通","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần","soHuu":["Huyết long"],"blurb":"Thần thông bao trùm hư vô trong bóng tối tuyệt đối, đối ứng với Tàn Dạ Thần Thông.","detail":"Huyết long thi triển Hắc Dạ Thần Thông bao trùm toàn bộ hư vô trong bóng tối, khiến bất kỳ tu sĩ nào chưa kịp tới gần chắc chắn bỏ mạng. Bị Tàn Dạ Thần Thông (thái sơ lực — quy tắc ánh sáng trời đất) của Vương Lâm phá khai.","congNang":["Bao trùm hư vô trong bóng tối tuyệt đối, giết kẻ xâm nhập"],"nguoiTu":[{"ten":"Huyết long","tuChuong":"@c1064","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1064","loai":"thi triển","importance":"normal","giaiDoan":"Huyết long thi triển","text":"Huyết long dùng Hắc Dạ Thần Thông bao trùm hư vô trong bóng tối để diệt Vương Lâm, bị Tàn Dạ Thần Thông phá khai.","anchor":"dưới Hắc Dạ thần Thông của nó, tu sĩ này chưa kịp tới gần chắc chắn sẽ bỏ mạng"}]},"nguon":["@c1064"]},{"id":"khanh-khong-luyen-tinh","name":"Khánh Không Luyện Tinh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Cổ Thần","soHuu":["Thác Sâm"],"blurb":"Khánh Không Luyện Tinh là một bí thuật của vương tộc Cổ Thần, có liên hệ với tinh điểm trên mi tâm. Vương Lâm nhận ra tên gọi của nó từ trí nhớ truyền thừa Cổ Thần nhưng không nắm được phương pháp thi triển. Thác Sâm khinh thường gọi nó là rác rưởi.","detail":"Khánh Không Luyện Tinh xuất thân từ bí thuật vương tộc Cổ Thần. Khi tinh điểm thứ ba trên mi tâm Thác Sâm phát sáng và bên trong mơ hồ giấu một vật, Vương Lâm nhận ra tên bí thuật này nhờ truyền thừa Cổ Thần trong trí nhớ, song không biết cách thi triển (@c1065). Thác Sâm khinh thường gọi nó là rác rưởi, ngụ ý bản thân sở hữu thứ mạnh hơn. Công năng cụ thể và phương pháp thi triển chưa được hé lộ trong tiến trình.","nguonGoc":"Bí thuật vương tộc Cổ Thần","thuocTinh":"Chưa rõ","congNang":["Liên quan đến tinh điểm Cổ Thần trên mi tâm; khi tinh điểm thứ ba phát sáng, bên trong mơ hồ giấu một vật @c1065"],"trangThai":"Được nhắc tên, chưa thi triển","capNhatToi":"@c1065","tabs":{"tienTrinh":[{"chuong":"@c1065","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu được nhắc tên","text":"Vương Lâm nhận ra tên Khánh Không Luyện Tinh từ trí nhớ truyền thừa Cổ Thần khi nhìn tinh điểm thứ ba trên mi tâm Thác Sâm phát sáng. Thác Sâm gọi bí thuật này là rác rưởi.","anchor":"hắn chỉ biết được tên, còn phương pháp thi triển cụ thể không có bên trong trí nhớ"}]},"nguon":["@c1065"],"dacDiem":"Bí thuật vương tộc Cổ Thần, gắn với tinh điểm trên mi tâm"},{"id":"tran-phap-truyen-tong-lien-minh-van-hai","name":"Trận pháp truyền tống Liên Minh → Vân Hải","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp truyền tống xuyên tinh vực cực lớn, quy mô ngàn trượng, bố trí sẵn dưới lớp tuyết trên bình nguyên tinh cầu hoang trong Liên Minh Tinh Vực, nối tới đại lục Mạc La bậc 5 thuộc Vân Hải Tinh Vực. Cần nguyên thần làm vật dẫn để kích hoạt, chỉ dùng được một lần rồi tự hủy hoàn toàn.","detail":"Trận pháp phức tạp được bố trí sẵn dưới lớp tuyết trên một bình nguyên tinh cầu hoang. Muốn kích hoạt phải bổ sung đá vào các vị trí rồi dùng một nguyên thần hôn mê làm vật dẫn: bấm quyết lên nguyên thần kéo dài thành vòng xoáy, trận pháp dồn toàn bộ sức mạnh vào vòng xoáy để tạo thành thông đạo tối đen truyền tống. Sau khi kích hoạt, trận pháp sụp đổ hoàn toàn, chỉ sử dụng được một lần duy nhất. Đầu bên kia là một trận pháp tiếp nhận đặt tại rừng phía bắc đại lục Mạc La. Vương Lâm từng quét sạch lớp tuyết ngàn trượng làm lộ trận pháp, bổ sung đá và dùng nguyên thần hôn mê làm vật dẫn để kích hoạt thông đạo (@c1067).","congNang":["Truyền tống xuyên tinh vực từ Liên Minh Tinh Vực tới Vân Hải Tinh Vực, đầu bên kia là trận pháp tiếp nhận ở rừng phía bắc đại lục Mạc La","Kích hoạt bằng cách bổ sung đá vào các vị trí và dùng nguyên thần hôn mê làm vật dẫn, bấm quyết kéo dài nguyên thần thành vòng xoáy tạo thông đạo tối đen (@c1067)"],"tabs":{"tienTrinh":[{"chuong":"@c1067","loai":"thi triển","importance":"major","giaiDoan":"Kích hoạt và tự hủy","text":"Vương Lâm quét tuyết ngàn trượng lộ trận pháp, bổ sung đá, dùng nguyên thần hôn mê làm vật dẫn kích hoạt thông đạo truyền tống xuyên tinh vực. Trận pháp sụp đổ sau khi dùng.","anchor":"Lấy hồn làm vật dẫn"}]},"nguon":["@c1067"],"uyLuc":"Dồn toàn bộ sức mạnh vào vòng xoáy tạo thông đạo truyền tống xuyên suốt hai tinh vực trong một lần kích hoạt.","dacDiem":"Quy mô ngàn trượng bố trí sẵn dưới lớp tuyết; cần nguyên thần làm vật dẫn; chỉ dùng được một lần rồi tự hủy hoàn toàn."},{"id":"tran-phap-tiep-nhan-mac-la","name":"Trận pháp tiếp nhận tại Mạc La","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp trong rừng phía bắc đại lục Mạc La, khoảng trống trăm trượng, là đầu tiếp nhận của trận truyền tống xuyên tinh vực từ Liên Minh.","detail":"Từng có nhóm tu sĩ thủ hộ nhưng đã bỏ đi ba tháng trước mà không phá hủy trận pháp, dường như mang theo hy vọng rằng ai đó sẽ tới. Trong đêm mưa sấm sét, trận pháp tự phát sáng lam khi nhận tín hiệu từ đầu bên kia.","congNang":["Tiếp nhận truyền tống xuyên tinh vực từ Liên Minh Tinh Vực"],"tabs":{"tienTrinh":[{"chuong":"@c1067","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát sáng đón người tới","text":"Trận pháp phát sáng lam trong đêm mưa sấm sét, báo hiệu Vương Lâm sắp xuất hiện tại Vân Hải Tinh Vực.","anchor":"từ trong trận truyền ra những tiếng rắc rắc"}]},"nguon":["@c1067"]},{"id":"trach-linh","name":"Trạch Linh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Quy Nguyên Tông","soHuu":["Chưởng môn Quy Nguyên Tông"],"blurb":"Trạch Linh là thần thông cổ xưa truyền thừa của Quy Nguyên Tông trên đại lục Mạc La, được mỗi đời chưởng môn thi triển trước khi chết để tuyển chọn Bạn Linh Tử. Người thi triển phải thiêu đốt nguyên thần, dung hợp thần thức vào thiên địa quy tắc để quét khắp toàn đại lục.","detail":"Trạch Linh là truyền thừa từ xa xưa của Quy Nguyên Tông. Khi thi triển, chưởng môn thiêu đốt nguyên thần, thần thức hòa vào thiên địa quy tắc rồi quét toàn bộ đại lục Mạc La để tìm Bạn Linh Tử (@c1068). Trong trạng thái dung hợp quy tắc này, người thi triển có thể nhìn thấy bản chất ẩn giấu của sự vật, chẳng hạn như oan hồn (@c1068). Đây là thần thông có tỉ lệ thành công cực thấp — trong vô số năm chỉ thành công hai lần — và chỉ dùng được một lần trước khi người thi triển chết. Lần thi triển cuối cùng của chưởng môn đương nhiệm đã thất bại, không tìm được Bạn Linh Tử.","thuocTinh":"Thần thức / Thiên địa quy tắc","nguonGoc":"Truyền thừa từ xa xưa của Quy Nguyên Tông","yeuCau":"Chưởng môn Quy Nguyên Tông, phải thiêu đốt nguyên thần (chết sau khi dùng)","uyLuc":"Thần thức dung hợp thiên địa quy tắc quét toàn đại lục, có thể nhìn thấy bản chất ẩn giấu.","dacDiem":"Tỉ lệ thành công cực thấp (chỉ hai lần trong vô số năm), phải thiêu đốt nguyên thần và chỉ dùng được một lần trước khi chết.","congNang":["Thiêu đốt nguyên thần, dung hợp thần thức vào thiên địa quy tắc để quét toàn đại lục Mạc La tìm Bạn Linh Tử @c1068","Trong trạng thái dung hợp quy tắc có thể nhìn thấy bản chất ẩn giấu của sự vật như oan hồn @c1068"],"nguoiTu":[{"ten":"Chưởng môn Quy Nguyên Tông","tuChuong":"@c1068","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1068","loai":"thi triển","importance":"major","giaiDoan":"Lần thi triển cuối cùng","text":"Chưởng môn Quy Nguyên Tông thiêu đốt nguyên thần thi triển Trạch Linh, quét toàn đại lục Mạc La tìm Bạn Linh Tử nhưng thất bại. Trong trạng thái dung hợp quy tắc phát hiện Vương Lâm với vô số oan hồn bao quanh.","anchor":"thi triển Trạch Linh, vì Quy Nguyên Tông ta mà tuyển ra một Bạn Linh Tử"}]},"capNhatToi":"@c1068","nguon":["@c1068"]},{"id":"phuong-phap-luyen-dan-van-hai","name":"Phương pháp luyện đan Vân Hải","cn":"","loai":"bi-thuat","loaiLabel":"Luyện đan thuật","phamCap":"Không rõ","hePhai":"Vân Hải Tinh Vực","soHuu":[],"blurb":"Phương pháp luyện đan phổ biến tại Vân Hải Tinh Vực, lấy hồn linh thú nhập thuốc luyện thành đan dược, chia mười ba bậc tương ứng mười ba bậc linh thú.","detail":"Lấy hồn của linh thú nhập vào thuốc, luyện thành đan dược chia làm mười ba bậc tương ứng mười ba bậc linh thú của Vân Hải Tinh Vực. Vương Lâm nghiên cứu qua ngọc giản lão tổ Quy Nguyên Tông, chứng thực phỏng đoán bằng Ly Hồn Đan cấp tám (phế đan), quyết tâm tự mình vận dụng phương pháp này nâng cao tu vi.","thuocTinh":"Luyện đan","nguonGoc":"Phổ biến tại Vân Hải Tinh Vực","congNang":["Lấy hồn linh thú nhập thuốc luyện đan, 13 bậc tương ứng 13 bậc linh thú"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1073","tangDatToi":"","trangThai":"đang nghiên cứu"}],"tabs":{"tienTrinh":[{"chuong":"@c1073","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Vương Lâm nghiên cứu chứng thực","text":"Vương Lâm nghiên cứu ngọc giản lão tổ Quy Nguyên Tông, tìm hiểu phương pháp luyện đan Vân Hải (hồn linh thú 13 bậc nhập thuốc), chứng thực phỏng đoán qua Ly Hồn Đan cấp tám (phế đan), quyết tâm tự mình dùng phương pháp này nâng cao tu vi.","anchor":"linh thú trong Vân Hải Tinh Vực có mười ba bậc, lấy hồn của linh thú nhập vào thuốc, luyện thành đan theo đó cũng chia làm mười ba bậc"}]},"nguon":["@c1073"]},{"id":"tu-phong","name":"Tử phong","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Tống Ngũ Đức"],"blurb":"Thần thông của Tống Ngũ Đức, phóng tử phong tràn ngập bốn phía chống đỡ Sát Lục Khí nhưng bị áp chế.","detail":"Tống Ngũ Đức phóng tử phong tràn ngập hướng bốn phía thổi ra, va chạm với Sát Lục Khí của Vương Lâm nhưng bị áp chế hoàn toàn.","nguon":["@c1074"]},{"id":"thuat-luyen-dan-vuong-lam","name":"Thuật luyện đan (Vương Lâm thi triển)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm dùng Thiên địa chi hỏa từ mắt trái tạo hỏa cầu thay lò luyện để luyện đan, không cần lò luyện hay đan phòng.","detail":"Lần đầu luyện đan tại Vân Hải Tinh Vực: dùng Thiên địa chi hỏa từ mắt trái tạo hỏa cầu ngưng tụ trước mặt thay thế lò luyện. Đan tạc lần đầu nhưng hỏa cầu chặn được toàn bộ lực xung kích, không ảnh hưởng bên ngoài.","thuocTinh":"hỏa","nguonGoc":"Vương Lâm tự sáng tạo dựa trên Thiên địa chi hỏa","dacDiem":"Không cần lò luyện, đan phòng; hỏa cầu tự chặn được lực xung kích khi đan tạc","congNang":["Thay thế lò luyện bằng hỏa cầu Thiên địa chi hỏa để luyện đan dược"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1077","tangDatToi":"Đan dược tầng ba (đan tạc)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1077","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng Thiên địa chi hỏa tạo hỏa cầu thay lò luyện, luyện đan dược tầng ba với thú hồn linh thú Lô Địch nhưng đan tạc lần đầu.","anchor":"Thiên địa chi hỏa theo hắn khống chế, giờ phút này ngọn lửa màu trắng gào thét lao ra"}]},"nguon":["@c1077"]},{"id":"ly-hon-dan-dan-phuong","name":"Ly Hồn Đan (đan phương)","cn":"离魂丹","loai":"bi-thuat","loaiLabel":"Đan phương","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đan phương Ly Hồn Đan, từ tầng sáu trở lên cần hồn phách mãnh thú và ba loại dược thảo trong đó có Vụ Trung Hoa.","detail":"Vương Lâm muốn luyện Ly Hồn Đan từ tầng sáu trở lên, cần hồn phách mãnh thú và ba loại dược thảo, trong đó Vụ Trung Hoa là loại quý hiếm chỉ mọc trên đại lục hoang dã ngoài tinh vực.","nguon":["@c1077"]},{"id":"than-thong-dieu-khien-nguyen-luc","name":"Thần thông điều khiển nguyên lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm minh ngộ từ hồi ức Đệ Tam Bộ trên La Thiên: không điều động mà cưỡng ép điều khiển nguyên lực thiên địa bốn phương tám hướng hóa thành công kích toàn bạo.","detail":"Vương Lâm trong lúc chiến đấu với khỉ đen ở Man Hoang nhớ lại cảnh lão giả hắc y Đệ Tam Bộ trên La Thiên vung tay ngăn chưởng Cổ Thần Thác Sâm, nhận ra không phải dùng lực bản thân điều động nguyên lực thiên địa mà là điều khiển — cưỡng ép nguyên lực bốn phương tám hướng tụ vào tay hóa công kích toàn bạo (@c1079). Tay trái liên tục điểm ba chỉ lên tay phải, đánh bật khỉ đen cấp năm, để lại ba khe nứt lan khắp toàn thân.","thuocTinh":"Nguyên lực thiên địa","nguonGoc":"Minh ngộ từ Đệ Tam Bộ của lão giả hắc y trên La Thiên","dacDiem":"Không dùng lực bản thân mà cưỡng ép điều khiển lực bên ngoài.","congNang":["Cưỡng ép nguyên lực thiên địa bốn phương tám hướng hóa thành công kích toàn bạo @c1079"],"uyLuc":"Đánh bật khỉ đen cấp năm đứng đỉnh phong, để lại ba khe nứt lan khắp toàn thân.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1079","tangDatToi":"","trangThai":"mới minh ngộ, chưa hoàn chỉnh"}],"tabs":{"tienTrinh":[{"chuong":"@c1079","loai":"xuất hiện","importance":"major","giaiDoan":"Minh ngộ lần đầu","text":"Vương Lâm nhớ cảnh lão giả hắc y Đệ Tam Bộ trên La Thiên vung tay ngăn chưởng Cổ Thần Thác Sâm, minh ngộ cảm giác điều khiển thay vì điều động nguyên lực thiên địa. Tay trái điểm ba chỉ lên tay phải, đánh bật khỉ đen cấp năm.","anchor":"hắn không phải dùng lực lượng của bản thân điều động nguyên lực thiên địa tiến vào, mà giống như đang điều khiển"}]},"capNhatToi":"@c1079","nguon":["@c1079"]},{"id":"tu-hon-vao-than","name":"Tụ hồn vào thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Khỉ đen khổng lồ"],"blurb":"Thần thông đặc hữu chỉ mãnh thú cấp sáu mới có — linh hồn hư ảo hiện trên đầu, hình dáng giống thú nhưng khá giống hình người.","detail":"Thần thông chỉ mãnh thú cấp sáu mới có. Khi đột phá, linh hồn hư ảo hiện trên đầu thú, hình dáng giống thú nhưng khá giống hình người. Linh hồn có thể tách ra hoặc nhập lại vào thân thể.","dacDiem":"Đặc hữu mãnh thú cấp sáu, linh hồn có thể tách/nhập thân","congNang":["Hiện linh hồn hư ảo tách/nhập thân thể"],"tabs":{"tienTrinh":[{"chuong":"@c1079","loai":"xuất hiện","importance":"normal","giaiDoan":"Khỉ đen đột phá cấp sáu","text":"Khỉ đen khổng lồ đột phá từ cấp năm lên cấp sáu dưới nguy cơ sinh tử, hiện thần thông Tụ hồn vào thân — linh hồn hư ảo xuất hiện trên đầu.","anchor":"đây chính là thần thông chỉ có ở những mãnh thú cấp sáu"}]},"capNhatToi":"@c1079","nguon":["@c1079"]},{"id":"khong-linh-an","name":"Khống Linh Ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật pháp thu phục mãnh thú thành linh thú — ngọc giản chứa ấn pháp bay ra, rơi lên mi tâm thú hóa ký hiệu lấp lánh rồi biến mất, hoàn tất thu phục.","detail":"Ngọc giản ghi Khống Linh Ấn bay ra từ tay Vương Lâm, rơi lên mi tâm khỉ đen hóa thành ký hiệu lấp lánh rồi biến mất, hoàn tất thu phục khỉ đen làm linh thú.","dacDiem":"Ngọc giản chứa ấn pháp, in ký hiệu lên mi tâm thú","congNang":["Thu phục mãnh thú thành linh thú"],"tabs":{"tienTrinh":[{"chuong":"@c1079","loai":"thi triển","importance":"normal","giaiDoan":"Thu phục khỉ đen cấp sáu","text":"Vương Lâm dùng Khống Linh Ấn thu phục khỉ đen đã đột phá cấp sáu — ngọc giản bay ra rơi lên mi tâm khỉ đen hóa ký hiệu lấp lánh rồi biến mất.","anchor":"Khống Linh Ấn từ trong tay Vương Lâm bay ra, ngọc giản rơi lên mi tâm khỉ đen hóa thành một ký hiệu lấp lánh"}]},"capNhatToi":"@c1079","nguon":["@c1079"]},{"id":"tran-phap-tam-dau-lau-ngu-doc-mon","name":"Trận pháp tám đầu lâu Ngũ Độc Môn","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Ngũ Độc Môn","soHuu":["Độc Bà Tử"],"blurb":"Trận pháp dùng tám đầu lâu khổng lồ lóe tia chớp xanh, dẫn động tử hồn trong Man Hoang đại lục ngưng tụ thành vật hữu hình rồi dung hợp tạo thần thông ác liệt vây hãm đối thủ.","detail":"Lão bà Ngũ Độc Môn thi triển trận pháp này tại sơn cốc trên Man Hoang đại lục. Tám đầu lâu khổng lồ bày thành trận, lóe tia chớp xanh, dẫn động tất cả linh hồn đã chết nhiều năm trong Man Hoang đại lục ngưng tụ lại. Tử hồn ngưng tụ thành vật hữu hình rồi dung hợp tạo thần thông ác liệt vây khốn Thi Lạc Hình. Tử hồn này khác thú hồn và sinh hồn, không thể dùng luyện đan.","congNang":["Dẫn động tử hồn ngưng tụ thành thần thông vây khốn đối phương"],"nguoiTu":[{"ten":"Độc Bà Tử","tuChuong":"@c1080","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1080","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Lão bà Ngũ Độc Môn thi triển trận pháp tám đầu lâu dẫn động tử hồn vây hãm Thi Lạc Hình trong sơn cốc Man Hoang đại lục.","anchor":"nó đã dẫn động tất cả những linh hồn đã chết nhiều năm trong Man Hoang đại lục ngưng tụ lại"}]},"nguon":["@c1080"]},{"id":"niet-khong-dan","name":"Niết Không Đan","cn":"","aliases":["Niến Không Đan"],"loai":"bi-thuat","loaiLabel":"Đan phương","phamCap":"Truyền thuyết","hePhai":"Phá Thiên Tông","soHuu":[],"blurb":"Đan dược trong truyền thuyết, phương pháp bào chế nằm trong ngọc giản Phá Thiên Tông tinh vực cấp tám, là nguyên nhân khiến toàn bộ tông phái tinh vực cấp sáu điên cuồng truy đuổi.","detail":"Niết Không Đan là đan dược truyền thuyết cực kỳ quý hiếm. Phương pháp bào chế được ghi trong ngọc giản của Phá Thiên Tông (tinh vực cấp tám). Công năng cụ thể chưa được tiết lộ, nhưng giá trị đủ lớn để gần như toàn bộ tông phái tinh vực cấp sáu ồ ạt truy đuổi tranh đoạt.","nguon":["@c1080"]},{"id":"doc-linh-an","name":"Độc Linh Ẩn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đỉnh phong thần thông","hePhai":"Ngũ Độc Môn","soHuu":["Độc Bà Tử"],"blurb":"Độc Linh Ẩn là thần thông đỉnh phong của Ngũ Độc Môn, thi triển bằng cách triệu hồi pho tượng Độc Vương cao trăm trượng, mắt tượng phóng u quang ngưng tụ thành dấu ấn đen ấn xuống đối thủ, hủy diệt cả thể xác lẫn nguyên thần.","detail":"Là tuyệt học của Ngũ Độc Môn, Độc Linh Ẩn triệu hồi pho tượng Độc Vương cao trăm trượng, mắt tượng phóng u quang ngưng tụ thành dấu ấn đen ấn xuống đối thủ. Kẻ bị đè trúng thì thân xác hóa bãi máu, nguyên thần bị độc tính phát tác chết ngay, diệt cả nguyên thần. Thần thông này từng được lão bà Ngũ Độc Môn thi triển trong trận chiến với Vương Lâm tại trung tâm Man Hoang đại lục @c1081.","congNang":["Triệu hồi tượng Độc Vương cao trăm trượng, mắt tượng phóng u quang ngưng tụ thành dấu ấn đen ấn xuống đối thủ, thân xác hóa bãi máu và nguyên thần bị độc tính phát tác chết ngay, diệt cả nguyên thần @c1081"],"nguoiTu":[{"ten":"Độc Bà Tử","tuChuong":"@c1081","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1081","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Lão bà Ngũ Độc Môn thi triển Độc Linh Ẩn trong trận chiến với Vương Lâm tại trung tâm Man Hoang đại lục, triệu hồi tượng Độc Vương cao trăm trượng phóng dấu ấn đen.","anchor":"Mời độc vương hiện thân! Độc Linh Ẩn!"}]},"nguon":["@c1081"],"uyLuc":"Dấu ấn đen từ tượng Độc Vương đè trúng khiến thân xác hóa bãi máu, nguyên thần bị độc tính phát tác chết ngay, hủy diệt cả thể xác lẫn nguyên thần đối thủ.","dacDiem":"Triệu hồi pho tượng Độc Vương cao trăm trượng, dùng u quang từ mắt tượng ngưng tụ dấu ấn đen mang độc tính hủy diệt cả thể xác lẫn nguyên thần."},{"id":"doc-cong-ngu-doc-mon","name":"Độc công Ngũ Độc Môn","cn":"","aliases":["Thần thông lão bà Ngũ Độc Môn"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngũ Độc Môn","soHuu":["Độc Bà Tử"],"blurb":"Hệ thống độc công của Ngũ Độc Môn gồm ba luồng khí (đám mây đỏ, mưa đen, con rắn đầu mào gà), Ấn Độc từ pho tượng hư ảo, và máu độc phản phệ. Kịch độc có thể giết tu sĩ Tịnh Niết hậu kỳ, ngang tầm Dục Tiên Dục Tử.","detail":"Ba luồng khí phun ra: luồng thứ nhất là đám mây đỏ, luồng thứ hai là mưa nước đen, luồng thứ ba là con rắn nhỏ đầu mào gà phun khí cực độc. Ngoài ra có Ấn Độc phóng từ ánh mắt pho tượng hư ảo, và tuyệt chiêu cắn đầu lưỡi phun máu độc. Kịch độc đủ sức giết tu sĩ Tịnh Niết hậu kỳ, được so sánh ngang Dục Tiên Dục Tử.","congNang":["Ba luồng khí (đám mây đỏ, mưa đen, con rắn đầu mào gà) tấn công từ xa","Ấn Độc từ pho tượng hư ảo đánh thẳng vào ngực đối thủ","Máu độc phản phệ khi bị ngăn phun (thối rữa thân thể)","Kịch độc giết tu sĩ Tịnh Niết hậu kỳ, ngang tầm Dục Tiên Dục Tử"],"nguoiTu":[{"ten":"Độc Bà Tử","tuChuong":"@c1082","tangDatToi":"","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1082","loai":"thi triển","importance":"normal","giaiDoan":"Lão bà Ngũ Độc Môn thi triển độc công đối đầu Vương Lâm","text":"Lão bà dùng ba luồng khí và Ấn Độc tấn công Vương Lâm nhưng lần lượt bị phá. Cắn đầu lưỡi chuẩn bị phun máu độc thì bị Định Thân Thuật trói, máu độc phản phệ thối rữa toàn thân.","anchor":"độc dược có thể g**t ch*t tu sĩ Tịnh Niết hậu kỳ rõ ràng là loại có thể so sánh với dục tiên tục tử"}]},"nguon":["@c1082"]},{"id":"pha-thien-tong-cap-tam","name":"Phá Thiên Tông cấp tám","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Cấp tám","hePhai":"Phá Thiên Tông","soHuu":["Vương Lâm"],"blurb":"Công pháp cấp tám của Phá Thiên Tông, được ghi trong một ngọc giản mà Vương Lâm phát hiện khi luyện hóa hài cốt đệ tử trong sơn cốc Man Hoang. Giá trị cực cao khiến nhiều tông phái, tu sĩ tranh đoạt.","detail":"Ngọc giản ghi rõ đây là công pháp cấp tám của Phá Thiên Tông, được Vương Lâm tìm thấy trong tro bụi sau khi dùng lửa luyện hóa hài cốt đệ tử (@c1083). Nội dung cụ thể của công pháp chưa được hé lộ trong tiến trình, song mức cấp tám đủ khiến các tu sĩ sống chết tranh đoạt.","nguon":["@c1083"],"thuocTinh":"","nguonGoc":"Phá Thiên Tông","congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c1083","loai":"xuất hiện","importance":"major","giaiDoan":"Ngọc giản được Vương Lâm tìm ra","text":"Vương Lâm dùng lửa luyện hóa hài cốt đệ tử, phát hiện ngọc giản ghi Phá Thiên Tông cấp tám bên trong tro bụi.","anchor":"Phá Thiên Tông cấp tám!"}]}},{"id":"mot-ngon-tay-thien-van-tu","name":"Một ngón tay của Thiên Vận Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tát Đậu Thành Binh (triệu hoán)","soHuu":["Vương Lâm"],"blurb":"Một ngón tay của Thiên Vận Tử là thần thông triệu hoán đạt tới cực hạn của Tát Đậu Thành Binh: dung nhập linh hồn Thiên Vận Tử vào thân thể, lấy ý niệm làm vật dẫn để triệu ra bàn tay khổng lồ giữa tinh không. Ngón trỏ điểm một chỉ với tốc độ không thể tưởng tượng, cắt ngang không gian và tiêu diệt nguyên thần tu sĩ Toái Niết.","detail":"Công pháp được Vương Lâm thi triển bằng cách dung nhập linh hồn Thiên Vận Tử vào thân thể, dùng ý niệm làm vật dẫn triệu hoán ngón tay Thiên Vận (@c1086). Khi phát động, một bàn tay khổng lồ xuất hiện trong tinh không, ngón trỏ giơ lên điểm một chỉ cắt ngang tất cả không gian phía trước, tiêu diệt nguyên thần Tiền Quý Chung ở cảnh giới Toái Niết. Sau khi điểm xong, cả ngón tay lẫn linh hồn Thiên Vận Tử đều biến mất.","congNang":["Dung nhập linh hồn Thiên Vận Tử vào thân thể, dùng ý niệm làm vật dẫn triệu hoán ngón tay Thiên Vận (@c1086)","Nhất chỉ xuyên không gian, cắt ngang tất cả không gian phía trước","Diệt nguyên thần tu sĩ cảnh giới Toái Niết"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1086","tangDatToi":"triệu hoán qua Tát Đậu Thành Binh cực hạn","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1086","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu triệu hoán","text":"Vương Lâm dung nhập linh hồn Thiên Vận Tử vào thân thể, dùng ý niệm làm vật dẫn triệu hoán ngón tay Thiên Vận Tử tiêu diệt nguyên thần Tiền Quý Chung. Linh hồn Thiên Vận Tử biến mất sau đòn này.","anchor":"Một ngón tay của Thiên Vận Tử đã cắt ngang tất cả không gian phía trước"}]},"capNhatToi":"@c1086","nguon":["@c1086"],"uyLuc":"Ngón trỏ điểm một chỉ với tốc độ không thể tưởng tượng, cắt ngang tất cả không gian phía trước và tiêu diệt nguyên thần tu sĩ Toái Niết.","dacDiem":"Triệu hoán bàn tay khổng lồ giữa tinh không qua việc dung nhập linh hồn Thiên Vận Tử; sau khi điểm xong thì ngón tay và linh hồn đều biến mất."},{"id":"tam-ton-that-kiep","name":"Tam Tổn Thất Kiếp","cn":"三损失劫","loai":"khac","loaiLabel":"Kiếp nạn","phamCap":"Kiếp nạn tộc Cổ Thần (ba tầng)","hePhai":"Cổ Thần","soHuu":[],"blurb":"Tam Tổn Thất Kiếp là hệ thống kiếp nạn sinh tử của tộc Cổ Thần, gồm ba tầng — Nhất Tổn (Lưỡng Kiếp), Nhị Tổn (Lưỡng Kiếp) và Tam Tổn (Tam Kiếp). Cổ Thần càng dũng mãnh thì Tổn Kiếp đến càng muộn, và việc vượt qua kiếp nạn quyết định sống chết cùng sự thăng tiến thực lực. (+) Hệ thống kiếp nạn của tam tộc cổ, gồm ba tổn bảy kiếp: đệ nhất tổn lưỡng kiếp, đệ nhị tổn lưỡng kiếp (thần kiếp và hồn kiếp), đệ tam tổn tam kiếp (Cổ Mạch Thương Khung Huyết, Cổ Đạo Tam Phân Thần, Cổ Tổ Chi Tứ). [CAN-SOAT-GOP] (+) Kiếp nạn đặc thù của Cổ Tộc gồm Tam Tổn, mỗi Tổn có nhiều kiếp con. Tộc nhân trưởng thành phải trải qua; hoàn thành có thể đạt Hồn Huyết. [CAN-SOAT-GOP]","detail":"Tam Tổn Thất Kiếp là kiếp nạn bắt buộc của Cổ Thần, tương đương Thiên Nhân Ngũ Suy của tu sĩ. Thông thường Cổ Thần từ lục tinh trở lên mới bắt đầu gặp, kẻ càng mạnh thì đến càng chậm, có thể tới thất tinh hoặc bát tinh mới gặp lần đầu. Đồ Ti tới bát tinh mới gặp và vượt qua dễ dàng, nhờ đó đạt bát tinh đỉnh phong. Tam Tổn là tầng kiếp cao nhất, hình dạng không rõ, ngay cả Đồ Ti cũng chưa biết. Hệ thống này được trình bày khi Vương Lâm ởngũ tinh gặp kiếp sớm bất thường @c1087.","congNang":["Kiếp nạn sinh tử bắt buộc của Cổ Thần, quyết định sống chết và thăng tiến thực lực","Gồm ba tầng kiếp: Nhất Tổn (Lưỡng Kiếp), Nhị Tổn (Lưỡng Kiếp), Tam Tổn (Tam Kiếp) @c1087","Cổ Thần càng dũng mãnh thì Tổn Kiếp đến càng muộn, thường lục tinh trở lên mới gặp @c1087","Vượt qua kiếp nạn giúp Cổ Thần thăng tiến, như Đồ Ti vượt kiếp đạt bát tinh đỉnh phong"],"tabs":{"tienTrinh":[{"chuong":"@c1087","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu giải thích chi tiết hệ thống Tam Tổn Thất Kiếp","text":"Hệ thống kiếp nạn Cổ Thần được trình bày: ba tầng kiếp, Cổ Thần mạnh đến muộn. Vương Lâm ngũ tinh gặp sớm bất thường — trường hợp đầu tiên trong ký ức Đồ Ti.","anchor":"Cổ Thần có Tam Tổn Thất Kiếp, giống như tu sĩ có Thiên Nhân Ngũ Suy vậy, đều là một con dao sinh mệnh trên đầu"}]},"nguon":["@c1087","@c1611","@c1942"],"dacDiem":"Cổ Thần càng mạnh thì kiếp đến càng muộn; Tam Tổn là tầng cao nhất, hình dạng không rõ, ngay cả Đồ Ti cũng chưa biết."},{"id":"nhat-ton-luong-kiep","name":"Nhất Tổn Lưỡng Kiếp","cn":"一损两劫","loai":"khac","loaiLabel":"Kiếp nạn","phamCap":"Tầng 1 của Tam Tổn Thất Kiếp","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Nhất Tổn Lưỡng Kiếp là tầng kiếp đầu tiên của Tam Tổn Thất Kiếp, gồm hai phần: Tổn (mất máu thịt cho đến khi chỉ còn xương) và Cốt Kiếp (xương cốt bị lực vô hình bóp nát từng phần). Vượt qua thành công sẽ ngưng tụ khung xương cứng hơn pháp bảo và thăng thực lực Cổ Thần, thất bại thì hình thần câu diệt.","detail":"Nhất Tổn Lưỡng Kiếp gồm hai phần. Phần Tổn: toàn thân liên tục mất máu thịt cho đến khi chỉ còn xương cốt. Phần Cốt Kiếp: lực vô hình bóp nát xương cốt từng phần từ chân lên. Nếu toàn bộ xương vỡ mà không phản kháng kịp thì bản tôn diệt vong. Nếu kiên trì đợi đến khoảnh khắc cuối cùng — khi tất cả xương vỡ — rồi mới phản kháng, khung xương sẽ ngưng tụ hoàn chỉnh, cứng hơn pháp bảo. Phần lớn Cổ Thần phản kháng sớm khi còn mảnh xương như móng tay nên giữ sơ hở vĩnh viễn. Trong nguyên tác, bản tôn Vương Lâm hoàn thành phần Tổn nhờ máu huyết Đồ Ti rồi bước vào Cốt Kiếp, khung xương phình lên (@c1087).","congNang":["Vượt qua thành công thì khung xương ngưng tụ cứng hơn pháp bảo, thăng thực lực Cổ Thần","Thất bại thì hình thần câu diệt","Phần Tổn: toàn thân liên tục mất máu thịt cho đến khi chỉ còn xương cốt","Phần Cốt Kiếp: lực vô hình bóp nát xương cốt từng phần từ chân lên"],"tabs":{"tienTrinh":[{"chuong":"@c1087","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm ngũ tinh đang chịu Nhất Tổn Lưỡng Kiếp","text":"Bản tôn Vương Lâm hoàn thành phần Tổn nhờ máu huyết Đồ Ti, bước vào Cốt Kiếp. Khung xương phình lên ba trăm trượng rồi bắt đầu bị phá hủy từ chân. Sau một tháng chân phải vỡ hoàn toàn, chân trái từ đầu gối xuống thành tro.","anchor":"Trong nháy mắt khi tất cả đã bị bản tôn hấp thu thì Tổn Kiếp đầu tiên kết thúc"}]},"nguon":["@c1087"],"uyLuc":"Vượt kiếp thành công ngưng tụ khung xương cứng hơn pháp bảo và thăng lên thực lực Cổ Thần","dacDiem":"Muốn khung xương ngưng tụ hoàn chỉnh phải kiên trì đợi đến khoảnh khắc toàn bộ xương vỡ mới phản kháng; phản kháng sớm sẽ giữ sơ hở vĩnh viễn"},{"id":"mac-luu-phan-than-thuat","name":"Mặc Lưu Phân Thần Thuật","cn":"墨流分神术","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":[],"blurb":"Công pháp cần tu luyện để Cổ Thần xung kích cửu tinh huyền thoại. Đồ Ti muốn tu luyện công pháp này.","detail":"Công pháp được nhắc đến liên quan đến Đồ Ti: muốn xung kích cửu tinh huyền thoại thì phải tu luyện Mặc Lưu Phân Thần Thuật.","nguon":["@c1087"]},{"id":"suu-hon","name":"Sưu Hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông cho phép lục ký ức từ nguyên thần đối phương, thu được toàn bộ thông tin bao gồm công pháp, chuyện đời và bí mật.","detail":"Vương Lâm dùng thần thức bùng phát phóng thẳng vào nguyên thần Độc Bà Tử để thi triển Sưu Hồn, lấy được toàn bộ ký ức gồm thuật luyện độc Ngũ Độc Môn, lai lịch ngọc giản chứa dấu ấn Tư Mã Mặc, và phương pháp luyện thú hồn biến dị.","congNang":["Lục toàn bộ ký ức từ nguyên thần đối phương","Trích ký ức nguyên thần khi đối phương bị trọng thương"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1091","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1091","loai":"thi triển","importance":"normal","giaiDoan":"Dùng lên nguyên thần Độc Bà Tử","text":"Vương Lâm thi triển Sưu Hồn lên nguyên thần Độc Bà Tử, lấy toàn bộ ký ức gồm thuật luyện độc, lai lịch ngọc giản Tư Mã Mặc, phương pháp luyện thú hồn biến dị.","anchor":"thần thức của hắn bùng ra rồi phóng thẳng vào nguyên thần này để thi triển thần thông Sưu Hồn"},{"chuong":"@c1132","loai":"thi triển","importance":"normal","giaiDoan":"Sưu hồn Thương Tùng Tử","text":"Vương Lâm lợi dụng Thương Tùng Tử bị trọng thương sắp điên cuồng mà dùng sưu hồn trích ký ức, thu thông tin về thế giới bảy màu và các mục tiêu.","anchor":"hắn lợi dụng cơ hội kẻ này bị trọng thương và sắp trở nên điên cuồng mà dùng pháp thuật sưu hồn"}]},"nguon":["@c1091","@c1132"]},{"id":"phuong-phap-luyen-thu-hon-bien-di","name":"Phương pháp luyện thú hồn biến dị","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngũ Độc Môn","soHuu":["Vương Lâm"],"blurb":"Phương pháp do thiên kiêu Ngũ Độc Môn sáng chế, dùng trận pháp cấm chế nhốt thú hồn và độc dược thúc đẩy chúng thôn phệ lẫn nhau, tạo hồn phách biến dị cấp cao hơn.","detail":"Dùng trận pháp cấm chế tạo nhà lao, nhốt thú hồn bên trong rồi dùng độc dược thúc đẩy chúng thôn phệ lẫn nhau, sinh ra hồn phách biến dị cấp cao hơn. Khuyết điểm: thú hồn biến dị chỉ có thể thôn phệ thú hồn biến dị khác chứ không thể thôn phệ thú hồn bình thường; xác suất thành công thấp; tiêu hao tài nguyên khổng lồ. Ngũ Độc Môn đã bỏ phương pháp này. Vương Lâm thử nghiệm thành công ở mức cấp 5 tại động phủ trên dãy núi Mạc La đại lục.","thuocTinh":"Độc","nguonGoc":"Do một thiên kiêu Ngũ Độc Môn sáng chế, sau đó bị bỏ vì tiêu hao quá lớn","dacDiem":"Thú hồn biến dị chỉ thôn phệ đồng loại biến dị, xác suất thấp, tiêu hao khổng lồ","congNang":["Tạo thú hồn biến dị cấp cao hơn bằng cách dùng độc thúc đẩy thú hồn thôn phệ lẫn nhau"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1091","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1091","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm thử nghiệm thành công cấp 5","text":"Vương Lâm dựa theo ký ức Độc Bà Tử luyện ra độc dược, đào động phủ trên dãy núi Mạc La đại lục, bố trí cấm chế nhốt thú hồn cấp 5 rồi dùng độc dược — thú hồn thôn phệ lẫn nhau thành công.","anchor":"dùng trận pháp cấm chế để hình thành một nhà lao vây khốn, nếu đặt vào bên trong một vài thú hồn dùng độc thúc đẩy"}]},"nguon":["@c1091"]},{"id":"lam-doc","name":"Lam Độc","cn":"","loai":"cong-phap","loaiLabel":"Độc công","phamCap":"Không rõ","hePhai":"Ngũ Độc Môn","soHuu":["Trừu Hải"],"blurb":"Độc công đặc trưng của đệ tử Ngũ Độc Môn, mắt lóe lam quang khi tu luyện.","detail":"Đệ tử Ngũ Độc Môn tu luyện lam độc, mắt phải lóe lam quang. Trừu Hải huyễn hóa bảy dấu ấn lam trên thân để phòng ngự, phá vỡ gió lạnh của Lữ Yến Phỉ. Có khả năng nhận biết dấu hiệu độc công trên người khác.","congNang":["Phòng ngự bằng dấu ấn lam trên thân","Nhận biết dấu hiệu độc công trên người khác"],"nguoiTu":[{"ten":"Trừu Hải","tuChuong":"@c1092","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1092","loai":"thi triển","importance":"normal","giaiDoan":"Trừu Hải sử dụng tại Quy Nguyên Tông","text":"Trừu Hải huyễn hóa bảy dấu ấn lam trên thân phòng ngự, phá vỡ gió lạnh của Lữ Yến Phỉ. Dùng lam quang quét kiểm tra đệ tử Quy Nguyên Tông, phát hiện dấu hiệu độc công.","anchor":"ánh mắt của những đệ tử Ngũ Độc Môn tu luyện lam độc"}]},"nguon":["@c1092"]},{"id":"than-thong-tieng-quat-phung-boi-son","name":"Thần thông tiếng quát của Phùng Bội Sơn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo Pháp Môn","soHuu":["Phùng Bội Sơn"],"blurb":"Thần thông ẩn chứa quy tắc thiên địa trong tiếng quát, đủ trấn áp cả một tông phái.","detail":"Phùng Bội Sơn quát một tiếng kinh thiên động địa, âm thanh ẩn chứa quy tắc thiên địa và thần thông kỳ dị, mặt đất rung chuyển, mây dồn lại. Toàn bộ đệ tử Quy Nguyên Tông miệng mũi trào máu, bốn cao thủ bao gồm Lữ Yến Phỉ và Lý Hướng Đông cũng phải khựng lại.","congNang":["Trấn áp diện rộng bằng âm thanh chứa quy tắc thiên địa"],"nguoiTu":[{"ten":"Phùng Bội Sơn","tuChuong":"@c1092","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1092","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp Quy Nguyên Tông","text":"Phùng Bội Sơn quát một tiếng khiến toàn bộ đệ tử Quy Nguyên Tông miệng mũi trào máu, bốn cao thủ phải khựng lại không dám phản kháng.","anchor":"trong âm thanh này có ẩn chứa quy tắc thiên địa và tồn tại một luồng thần thông vô cùng kỳ dị"}]},"nguon":["@c1092"]},{"id":"y-canh-dao","name":"Ý Cảnh đạo","cn":"意境道","loai":"than-thong","loaiLabel":"Thần thông / Cảnh giới đạo","phamCap":"Cực cao (chỉ đại trưởng lão Đạo Pháp Môn mới đạt)","hePhai":"Đạo","soHuu":["Vương Lâm"],"blurb":"Ý Cảnh đạo là cảnh giới đạo tùy thân động — người thi triển đứng ở đâu thì nơi đó hóa thành đạo. Khi triển khai, thiên địa hư ảo thật giả đan xen, uy áp cực mạnh khiến đối phương cảm thấy mình nhỏ bé vô cùng trong đất trời.","detail":"Ý Cảnh đạo do Vương Lâm tự nhiên phát ra khi bước ra từ khu vườn phía nam Quy Nguyên Tông (@c1093), không cần xuất toàn lực mà đạo bùng ra theo lời nói. Phùng Bội Sơn, đệ tử hạch tâm Đạo Pháp Môn, nhận ra đây là cảnh giới đạo tùy thân động — trong Đạo Pháp Môn chỉ đại trưởng lão cao nhất môn phái mới đạt được thần thông này.","congNang":["Thiên địa hư ảo thật giả đan xen, uy áp cực mạnh khiến đối phương cảm thấy mình nhỏ bé trong đất trời @c1093","Đạo bùng ra tự nhiên theo lời nói, không cần xuất toàn lực @c1093"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1093","tangDatToi":"đạo tùy thân động","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1093","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm thi triển lần đầu","text":"Vương Lâm bước ra từ khu vườn phía nam Quy Nguyên Tông, tự nhiên phát ra Ý Cảnh đạo, thiên địa hư ảo thật giả đan xen. Phùng Bội Sơn nhận ra đây là đạo tùy thân động, cảnh giới chỉ đại trưởng lão Đạo Pháp Môn mới đạt. Uy áp khiến Trừu Hải, Triệu Vũ, Phùng Bội Sơn khiếp sợ.","anchor":"đại trưởng lão cao nhất môn phái mới có được thần thông “đạo tùy thân động” thế này"}]},"nguon":["@c1093"],"uyLuc":"Uy áp cực mạnh khiến đối phương cảm thấy mình nhỏ bé vô cùng trong đất trời.","dacDiem":"Cảnh giới đạo tùy thân động — đứng ở đâu thì nơi đó là đạo; trong Đạo Pháp Môn chỉ đại trưởng lão cao nhất mới đạt được."},{"id":"phuong-phap-luyen-thu-doc-ba-tu","name":"Phương pháp luyện thú (từ ký ức Độc Bà Tử)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Độc/Thú","soHuu":["Vương Lâm"],"blurb":"Phương pháp luyện thú có trong ký ức Độc Bà Tử. Vương Lâm đang mạo hiểm thử nghiệm để chuẩn bị cho việc vào Phong Tiên Giới.","detail":"Vương Lâm đang mạo hiểm thử nghiệm phương pháp luyện thú lấy từ ký ức Độc Bà Tử. Nếu thành công sẽ tăng cơ hội vào Phong Tiên Giới. Địa điểm luyện thú có thần thức cấm chế do Vương Lâm bố trí, chỉ cần động niệm có thể hủy diệt toàn bộ bên trong.","congNang":["Luyện thú để chuẩn bị vào Phong Tiên Giới"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1093","tangDatToi":"đang thử nghiệm","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1093","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm bắt đầu thử nghiệm","text":"Vương Lâm mạo hiểm thử nghiệm phương pháp luyện thú trong ký ức Độc Bà Tử, bố trí thần thức cấm chế tại địa điểm luyện thú.","anchor":"mạo hiểm thử nghiệm phương pháp luyện thú trong ký ức của Độc Bà Tử"}]},"nguon":["@c1093"]},{"id":"y-canh-buoc-chan-cua-lo-van-tong","name":"Ý cảnh bước chân của Lô Vân Tòng","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông ý cảnh","phamCap":"không rõ","hePhai":"Ý cảnh","soHuu":["Lô Vân Tòng"],"blurb":"Thần thông ý cảnh của Lô Vân Tòng, dung nhập ý cảnh vào từng bước chân để mượn lực thiên địa tạo uy áp. Khi dùng đối đầu Vương Lâm, nó bị phá tan chỉ bởi một chữ “Ngồi”.","detail":"Mỗi bước chân của Lô Vân Tòng đều do ý cảnh biến thành, tiến lên là dùng ý cảnh tấn công và có thể uy hiếp đạo niệm đối phương. Trong lần xâm nhập dược viện Quy Nguyên Tông, thế công này khiến bầu trời phía sau hắn âm u, nhưng toàn bộ bị đạo niệm của Vương Lâm áp đảo.","thuocTinh":"Ý cảnh","uyLuc":"Có thể tấn công đạo niệm, khiến đạo cơ và nguyên thần đối phương chịu uy hiếp.","dacDiem":"Thi triển thông qua từng bước chân dung nhập thiên địa.","congNang":["Dung nhập ý cảnh vào thiên địa qua bước chân để tạo uy áp và tấn công đạo niệm đối phương @c1095"],"nguoiTu":[{"ten":"Lô Vân Tòng","tuChuong":"@c1095","tangDatToi":"không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1095","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Vương Lâm","text":"Lô Vân Tòng thi triển ý cảnh qua từng bước chân để tấn công đạo niệm Vương Lâm, nhưng bị phá tan ngay trong cuộc đối đầu.","anchor":"mỗi bước chân hắn tiến lên đều do ý cảnh biến thành, mỗi bước tiến về phía trước đều dùng ý cảnh tấn công"}]},"dinhDanh":"goc","capNhatToi":"@c1095","nguon":["@c1095"]},{"id":"con-duong-dao-cua-vuong-lam","name":"Con đường đạo của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Tổng kết ý cảnh","phamCap":"không rõ","hePhai":"Ý cảnh","soHuu":["Vương Lâm"],"blurb":"Lộ trình ý cảnh của Vương Lâm được tổng kết từ Sinh Tử Luân Hồi đến Chân Giả Ý Cảnh. Đây là nền tảng khiến đạo niệm của Lô Vân Tòng không thể so sánh với hắn.","detail":"Con đường đạo của Vương Lâm từng trải qua Sinh Tử Luân Hồi trong thời gian dài, chuyển thành Nhân Quả Tuần Hoàn, rồi Nhân Quả Viên Mãn và Chân Giả Ý Cảnh. Chương này dùng tổng kết ấy để đối chiếu trực tiếp với đạo niệm của Lô Vân Tòng.","thuocTinh":"Ý cảnh, Sinh Tử, Nhân Quả, Chân Giả","dacDiem":"Là tiến trình ý cảnh tích lũy qua nhiều giai đoạn cảm ngộ.","congNang":["Tổng kết nền tảng đạo niệm giúp Vương Lâm áp đảo ý cảnh của Lô Vân Tòng @c1095"],"cacTang":[{"ten":"Sinh Tử Luân Hồi","moTa":"Giai đoạn Vương Lâm cảm ngộ trong năm trăm năm.","chuong":"@c1095"},{"ten":"Nhân Quả Tuần Hoàn","moTa":"Giai đoạn chuyển hóa sau chín trăm năm.","chuong":"@c1095"},{"ten":"Nhân Quả Viên Mãn","moTa":"Giai đoạn tiếp nối sau Nhân Quả Tuần Hoàn.","chuong":"@c1095"},{"ten":"Chân Giả Ý Cảnh","moTa":"Giai đoạn chuyển hóa tiếp theo trong lộ trình ý cảnh của Vương Lâm.","chuong":"@c1095"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1095","tangDatToi":"Chân Giả Ý Cảnh","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1095","loai":"nhắc tới","importance":"normal","giaiDoan":"Tổng kết đạo niệm","text":"Lộ trình ý cảnh của Vương Lâm được nêu ra để cho thấy đạo niệm của hắn vượt xa Lô Vân Tòng.","anchor":"sau chín trăm năm thì Sinh Tử Luân Hồi trở thành Nhân Quả Tuần Hoàn, sau nhiều năm lại trở nên Nhân Quả Viên Mãn, lại một lần nữa chuyển hóa thành Chân Giả Ý Cảnh"}]},"dinhDanh":"goc","capNhatToi":"@c1095","nguon":["@c1095"]},{"id":"y-canh-buoc-chan","name":"Ý cảnh bước chân","cn":"","aliases":["thần thông ý cảnh"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ý cảnh","soHuu":["Vương Lâm"],"blurb":"Ý cảnh bước chân là thần thông Vương Lâm ngộ ra từ phương pháp ý cảnh thiên địa của Lô Vân Tòng. Khi thi triển, bước chân của hắn đồng bộ với nhịp tim đối thủ và gây áp lực trực tiếp lên tâm thần.","detail":"Thần thông này dùng bước chân và ý cảnh để khống chế nhịp tim, tâm thần của đối phương. Trong lần đối phó Dương Ngọc, mỗi bước của Vương Lâm đều như búa tạ giáng vào tâm thần, ép đối thủ phun máu, rơi vào ảo giác và phải cầu cứu.","thuocTinh":"Ý cảnh","nguonGoc":"Vương Lâm ngộ từ phương pháp ý cảnh thiên địa của Lô Vân Tòng.","uyLuc":"Có thể ép tu sĩ Tịnh Niết trung kỳ phun máu, rơi vào ảo giác và mất khả năng chống đỡ.","dacDiem":"Lấy bước chân làm tiết tấu, đồng bộ nhịp tim đối phương để tạo áp lực tâm thần.","congNang":["Dùng bước chân và ý cảnh khống chế nhịp tim cùng tâm thần đối phương @c1100","Có thể khiến đối phương rơi vào ảo giác dữ dội @c1100"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1100","tangDatToi":"đại thành","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1100","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu ghi nhận thi triển","text":"Vương Lâm dùng Ý cảnh bước chân chế ngự Dương Ngọc, ép đối phương phun máu và rơi vào ảo giác.","anchor":"Phương pháp đó chính la một loại vận dụng ý cảnh của Lô Vân Tòng, nhưng với những hiểu biết của Vương Lâm về đạo thì rất nhanh đã tìm ra được, cuối cùng lại trở thành một thần thông của chính mình"}]},"trangThai":"đang dùng","capNhatToi":"@c1100","dinhDanh":"goc","nguon":["@c1100"]},{"id":"anh-mat-song-hu-thuc","name":"Ánh mắt song hư thực","cn":"","aliases":["mắt trái hư ảo, mắt phải chớp giật"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Ánh mắt song hư thực là thần thông Vương Lâm thi triển khi nói một chữ Đạo. Hai mắt hóa thành hai trạng thái khác biệt, đánh thẳng vào mắt và tâm thần đối phương.","detail":"Khi thi triển, mắt trái của Vương Lâm trở nên hư ảo, mắt phải như chớp giật, hai luồng ánh mắt khác biệt đâm thẳng vào mắt đối thủ. Tên tu sĩ Tịnh Niết sơ kỳ bị ảnh hưởng liền rơi vào ảo giác, không phân biệt thật giả, máu trào khóe miệng và ôm đầu la thảm.","thuocTinh":"Hư thực, ảo giác","uyLuc":"Có thể làm tu sĩ Tịnh Niết sơ kỳ rơi vào ảo giác và mất khả năng khống chế pháp bảo.","dacDiem":"Kết hợp biến hóa hai mắt với một chữ Đạo để đánh thẳng vào cảm tri đối phương.","congNang":["Gây ảo giác mạnh khiến đối thủ không phân biệt thật giả @c1100"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1100","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1100","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong giao chiến","text":"Vương Lâm dùng Ánh mắt song hư thực cùng một chữ Đạo khiến một tu sĩ Tịnh Niết sơ kỳ rơi vào ảo giác và bị phế.","anchor":"Hai mắt Vương Lâm đột nhiên biến đổi, mắt trái trở nên hư ảo, mắt phải như chớp giật phóng đi đánh tan sắt đá"}]},"trangThai":"đang dùng","capNhatToi":"@c1100","dinhDanh":"goc","nguon":["@c1100"]},{"id":"than-thong-ba-chi","name":"Thần thông ba chỉ","cn":"","aliases":["Thần thông ba chỉ học từ Lỗ Phu Tử"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu","hePhai":"Lỗ Phu Tử truyền thừa","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm học từ Lỗ Phu Tử, dùng ba chỉ liên tiếp dẫn động nguyên lực thiên địa theo phạm vi tăng dần để tạo lực công kích cực mạnh.","detail":"Khi đối đầu Ngô Thanh, Vương Lâm vỗ tay phải lên hư không rồi dùng hai ngón tay trái điểm ba chỉ lên mu bàn tay phải. Mỗi chỉ dẫn động nguyên lực thiên địa trong phạm vi rộng hơn, từ vài vạn dặm đến mười vạn dặm rồi lan khắp Bồng Lai, phá tan vòng xoáy của Ngô Thanh và nghiền nát các bảo vật được lấy ra ngăn cản. Thần thông này được ghi nhận là Vương Lâm học từ Lỗ Phu Tử, dù chưa đạt mức tinh túy nhưng với Ngô Thanh thì đã không đủ tư cách chống cự.","nguon":["@c1104"]},{"id":"than-thong-quai-di-chuong-dieu-khien-thien-dia-nguyen-luc","name":"Thần thông quái dị chưởng điều khiển thiên địa nguyên lực","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Vương Lâm"],"blurb":"Một chưởng chưa rõ tên của Vương Lâm được Lý Thiến Mai chú ý vì có thể điều khiển thiên địa nguyên lực. Bên trong thần thông này uẩn hàm ý nô dịch, khác với Dịch Linh Ấn đã lộ diện.","detail":"Lý Thiến Mai quan sát từ xa và nhận định một chưởng trước đó của Vương Lâm rất quái dị, không rõ thuộc thần thông nào, nhưng có khả năng điều khiển thiên địa nguyên lực và mang tính nô dịch.","thuocTinh":"Điều khiển thiên địa nguyên lực","uyLuc":"Có thể khiến Lý Thiến Mai nhận ra điểm khác thường ngoài Dịch Linh Ấn.","dacDiem":"Uẩn hàm sự nô dịch trong khi vận dụng thiên địa nguyên lực.","congNang":["Điều khiển thiên địa nguyên lực và uẩn hàm ý nô dịch @c1105"],"dinhDanh":"goc","capNhatToi":"@c1105","tabs":{"tienTrinh":[{"chuong":"@c1105","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Lý Thiến Mai nhận ra điểm dị thường","text":"Lý Thiến Mai chú ý một chưởng của Vương Lâm có thể điều khiển thiên địa nguyên lực, bên trong uẩn hàm sự nô dịch.","anchor":"một chưởng trước đó của người này lại rất quái dị, không biết là thần thông gì mà có thể điều khiển thiên địa nguyên lực"}]},"nguon":["@c1105"]},{"id":"than-thong-am-hon-cua-van-hon-tu","name":"Thần thông âm hồn của Vân Hồn Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Toái Niết trung kỳ","hePhai":"","soHuu":["Vân Hồn Tử"],"blurb":"Thần thông dùng hồn làm chủ của Vân Hồn Tử, có thể tung âm hồn vô tận công kích đối thủ.","detail":"Khi thi triển, âm hồn cuồn cuộn nghiêng trời lệch đất tấn công Vương Lâm. Sau khi thu lại, chúng ngưng tụ thành chín ngọn lửa linh hồn khổng lồ vờn quanh sau lưng Vân Hồn Tử.","thuocTinh":"Hồn","uyLuc":"Đủ ép Vương Lâm phải lùi năm bước khi hắn chủ động giữ lại một phần lực.","dacDiem":"Dùng âm hồn và lửa linh hồn làm hình thái công kích.","congNang":["Tấn công bằng đám âm hồn vô tận và thu lại thành chín ngọn lửa linh hồn @c1109"],"nguoiTu":[{"ten":"Vân Hồn Tử","tuChuong":"@c1109","tangDatToi":"Toái Niết trung kỳ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1109","loai":"thi triển","importance":"normal","giaiDoan":"Thử tu vi Vương Lâm","text":"Vân Hồn Tử thi triển thần thông âm hồn tấn công Vương Lâm rồi thu lại thành chín ngọn lửa linh hồn sau lưng.","anchor":"thần thông của kẻ kia dùng hồn làm chủ, rõ ràng là người ác ma thanh danh hiển hách"}]},"capNhatToi":"@c1109","nguon":["@c1109"]},{"id":"thuat-an-dau-dich-thu-tong","name":"Thuật ẩn dấu Dịch Thú Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Dịch Thú Tông","soHuu":["Trần Thiên Quân"],"blurb":"Đặc kỹ che giấu khí tức của Dịch Thú Tông, được Trần Thiên Quân dùng để ẩn nấp ngay trước nhóm lão quái.","detail":"Trần Thiên Quân đến từ lâu nhưng không ai trong nhóm phát hiện, kể cả Thương Tùng Tử. Khi hắn lộ diện, Thương Tùng Tử khen thuật ẩn dấu của Dịch Thú Tông quả nhiên cao minh.","thuocTinh":"Ẩn giấu","uyLuc":"Có thể khiến nhiều tu sĩ Toái Niết trung kỳ không phát hiện người thi triển đã đến gần.","dacDiem":"Che giấu khí tức và sự tồn tại rất sâu.","congNang":["Che giấu khí tức đến mức nhóm lão quái không phát hiện Trần Thiên Quân đã đến từ trước @c1109"],"nguoiTu":[{"ten":"Trần Thiên Quân","tuChuong":"@c1109","tangDatToi":"Đang dùng","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1109","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn nấp tại nơi tụ hội","text":"Trần Thiên Quân dùng thuật ẩn dấu của Dịch Thú Tông để đến trước mà nhóm lão quái không phát hiện.","anchor":"Thuật ẩn dấu của Dịch Thú Tông quả nhiên cao minh, lão phu cũng không thể phát hiện ra"}]},"capNhatToi":"@c1109","nguon":["@c1109"]},{"id":"than-thong-luyen-hoa-manh-thu-dich-thu-tong","name":"Thần thông luyện hóa mãnh thú Dịch Thú Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Dịch Thú Tông","soHuu":["Trần Thiên Quân"],"blurb":"Thần thông của Trần Thiên Quân dùng để giết mãnh thú, rút linh hồn và luyện thành đan dược đen.","detail":"Trần Thiên Quân khiến vài trăm mãnh thú tan vỡ, linh hồn của chúng ngưng tụ thành cơn lốc đen rồi bị luyện hóa thành một viên đan dược đen để hắn nuốt vào.","thuocTinh":"Thú hồn","uyLuc":"Có thể xử lý vài trăm mãnh thú cùng lúc và luyện hóa linh hồn ngay tại chỗ.","dacDiem":"Biến linh hồn mãnh thú thành đan dược đen bổ sung cho người thi triển.","congNang":["Giết mãnh thú, gom linh hồn thành cơn lốc đen rồi luyện thành đan dược đen @c1109"],"nguoiTu":[{"ten":"Trần Thiên Quân","tuChuong":"@c1109","tangDatToi":"Đang dùng","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1109","loai":"thi triển","importance":"normal","giaiDoan":"Luyện hóa đàn mãnh thú","text":"Trần Thiên Quân giết đàn mãnh thú đi theo mình, gom linh hồn thành cơn lốc đen rồi luyện thành đan dược để nuốt.","anchor":"tất cả hóa thành một cơn gió lốc màu đen"}]},"capNhatToi":"@c1109","nguon":["@c1109"]},{"id":"tu-son-tran","name":"Tứ Sơn trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Thương Tùng Tử"],"blurb":"Tứ Sơn trận là trận pháp hình thành từ bốn ngọn núi ở bốn phương đông tây nam bắc của Man Hoang đại lục, được Thương Tùng Tử kích hoạt để bóc lớp đất đá che phủ và làm lộ ký hiệu khổng lồ trên mặt đất.","detail":"Trận thế do bốn ngọn núi ở bốn phương của Man Hoang đại lục cùng tạo thành, bao phủ một khu vực rộng lớn trên đại lục. Khi được Thương Tùng Tử vận chuyển kích hoạt, hào quang từ bốn ngọn núi khuếch tán rồi nối liền với nhau, bóc từng tầng đất đá bay lên tiêu tán, để lộ ký hiệu khổng lồ ẩn dưới mặt đất Man Hoang đại lục @c1110.","dinhDanh":"goc","congNang":["Bóc lớp đất đá che phủ để lộ ký hiệu khổng lồ trên mặt đất Man Hoang đại lục @c1110"],"dacDiem":"Bốn ngọn núi đông tây nam bắc cùng tạo thành trận thế bao phủ khu vực rộng lớn trên đại lục.","tabs":{"tienTrinh":[{"chuong":"@c1110","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt trên Man Hoang đại lục","text":"Thương Tùng Tử kích hoạt Tứ Sơn trận, khiến bốn ngọn núi nối hào quang và bóc sạch lớp che phủ để lộ ký hiệu khổng lồ.","anchor":"những luồng hào quang bùng ra trên bốn ngọn núi đang khuếch tán và nổi lên với nhau tạo thành Tứ Sơn trận"}]},"capNhatToi":"@c1110","nguon":["@c1110"]},{"id":"tien-tran-tren-man-hoang-dai-luc","name":"Tiên trận trên Man Hoang đại lục","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Thương Tùng Tử"],"blurb":"Tiên trận trên Man Hoang đại lục làký hiệu khổng lồ do Thương Tùng Tử bố trí,ẩn dưới lớp đất đá và bao trùm gần toàn bộ đại lục. Khi được kích hoạt bằng vài chục vạn tiên ngọc, ký hiệu sáng rực, khiến cả đại lục dịch chuyển khỏi vị trí cũ.","detail":"Tiên trận được Thương Tùng Tử bố trí trên Man Hoang đại lục nhằm che giấu và mở vết nứt bảy màu. Nó là ký hiệu khổng lồ nằm dưới lớp đất đá, chiếm gần toàn bộ đại lục, và khi sáng lên có thể bao trùm phạm vi cả đại lục. Sau khi hấp thu tiên lực từ vài chục vạn tiên ngọc, tiên trận kích hoạt khiến đại lục rời vị trí cũ, đồng thời kiềm chế vết nứt bảy màu để nó không tan vỡ khi bị đại lục cưỡng ép mở rộng (@c1110).","dinhDanh":"goc","nguonGoc":"Do Thương Tùng Tử bố trí trên Man Hoang đại lục để che giấu và mở vết nứt bảy màu.","congNang":["Hấp thu tiên lực từ tiên ngọc để kích hoạt và dịch chuyển toàn bộ Man Hoang đại lục @c1110","Kiềm chế vết nứt bảy màu để nó không tan vỡ khi bị đại lục cưỡng ép mở rộng @c1110"],"dacDiem":"Là ký hiệu khổng lồ ẩn dưới lớp đất đá, khi sáng lên có thể bao trùm phạm vi cả đại lục.","tabs":{"tienTrinh":[{"chuong":"@c1110","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt ký hiệu đại lục","text":"Thương Tùng Tử dùng vài chục vạn tiên ngọc kích hoạt tiên trận, khiến Man Hoang đại lục chuyển động và chuẩn bị đâm vào vết nứt bảy màu.","anchor":"ký hiệu trên đại lục này sẽ kiềm chế vết nứt để nó không bị tan vỡ"}]},"capNhatToi":"@c1110","nguon":["@c1110"],"uyLuc":"Kích hoạt bằng vài chục vạn tiên ngọc, đủ sức làm dịch chuyển toàn bộ Man Hoang đại lục khỏi vị trí cũ @c1110"},{"id":"luc-luong-co-than","name":"Lực lượng Cổ thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cổ thần","soHuu":["Vương Lâm"],"blurb":"Lực lượng thân thể Cổ thần được Vương Lâm vận vào một quyền khi tiến vào vết nứt bảy màu.","detail":"Trong khoảnh khắc Vân Hồn Tử bị Định Thân Thuật khóa lại, Vương Lâm đánh ra một quyền chứa lực lượng Cổ thần, khiến vết nứt bên cạnh đối phương xiêu vẹo trên diện rộng và làm lệch vị trí truyền tống.","thuocTinh":"Cổ thần","uyLuc":"Có thể làm nhiễu vết nứt truyền tống khi bùng nổ đúng thời điểm.","dacDiem":"Được dùng phối hợp với Định Thân Thuật và kiếm quang để phá thế liên thủ của Thương Tùng Tử.","congNang":["Làm vết nứt bên cạnh mục tiêu xiêu vẹo, gây sai lệch vị trí truyền tống @c1111"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1111","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1111","loai":"thi triển","importance":"normal","giaiDoan":"Một quyền Cổ thần","text":"Vương Lâm đánh ra một quyền chứa lực lượng Cổ thần làm vết nứt bên cạnh Vân Hồn Tử xiêu vẹo.","anchor":"lực lượng Cổ thần ẩn chứa biên trong nổ ầm lên một tiếng rồi lao về phía Vân Hồn Tử"}]},"dinhDanh":"goc","capNhatToi":"@c1111","nguon":["@c1111"]},{"id":"ngon-lua-linh-hon-cua-van-hon-tu","name":"Ngọn lửa linh hồn của Vân Hồn Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vân Hồn Tử"],"blurb":"Thần thông linh hồn được Vân Hồn Tử dùng để chống lại kiếm quang của Vương Lâm.","detail":"Vân Hồn Tử vận ngọn lửa linh hồn hóa thành sương đỏ và đầu lâu, muốn thôn phệ kiếm quang do Vương Lâm chém ra khi mọi người chuẩn bị vào vết nứt bảy màu.","thuocTinh":"linh hồn","uyLuc":"Có thể hóa thành sương đỏ và đầu lâu để thôn phệ kiếm quang.","dacDiem":"Được dùng trong lúc Vân Hồn Tử bị tập kích bất ngờ trước vết nứt.","congNang":["Hóa thành sương đỏ và đầu lâu để đối kháng, thôn phệ kiếm quang @c1111"],"nguoiTu":[{"ten":"Vân Hồn Tử","tuChuong":"@c1111","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1111","loai":"thi triển","importance":"normal","giaiDoan":"Chống kiếm quang","text":"Vân Hồn Tử dùng ngọn lửa linh hồn hóa thành sương đỏ và đầu lâu để thôn phệ kiếm quang của Vương Lâm.","anchor":"ngọn lửa linh hồn lại lập tức thành một đám sương màu đỏ, lại tạo thành một đầu lâu"}]},"dinhDanh":"goc","capNhatToi":"@c1111","nguon":["@c1111"]},{"id":"nhat-nguyet-hoi-dao","name":"Nhật Nguyệt Hồi Đạo","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Đoan Mộc đồng tử"],"blurb":"Công pháp Đoan Mộc đồng tử tu luyện, lấy cảm ngộ quay về ký ức làm trọng tâm.","detail":"Nhật Nguyệt Hồi Đạo cần cảm ngộ chín lần quay về ký ức mới thành đạo, vì vậy Hồi đan có giá trị trực tiếp đối với Đoan Mộc.","nguon":["@c1112"],"thuocTinh":"Hồi tưởng ký ức","dacDiem":"Liên hệ trực tiếp với Hồi đan và quá trình tìm thiên đạo trong ký ức.","nguoiTu":[{"ten":"Đoan Mộc đồng tử","tuChuong":"@c1112","tangDatToi":"Không rõ","trangThai":"đang tu"}],"congNang":["Giúp người tu cảm ngộ chín lần quay về ký ức để thành đạo @c1112"],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"xuất hiện","importance":"normal","giaiDoan":"Liên hệ Hồi đan","text":"Thương Tùng Tử nêu rõ Đoan Mộc tu luyện Nhật Nguyệt Hồi Đạo nên Hồi đan có ích cho ý cảnh cảm ngộ của hắn.","anchor":"Đoan Mộc đạo hữu tu luyện Nhật Nguyệt Hồi Đạo, ý cảnh cảm ngộ chính là lúc này"}]}},{"id":"hoi-dai-tu-tai","name":"Hồi Đại Tự Tại","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Đoan Mộc đồng tử"],"blurb":"Thần thông của Đoan Mộc đồng tử được Thương Tùng Tử tính tới để hỗ trợ chuyến đi trong thế giới bảy màu.","detail":"Hồi Đại Tự Tại có thể trợ giúp đoàn người mở đường qua khu vực sương mù và mãnh thú, là lý do quan trọng khiến Thương Tùng Tử mời Đoan Mộc tham gia.","nguon":["@c1112"],"congNang":["Hỗ trợ mở đường và trợ giúp hành trình trong thế giới bảy màu @c1112"],"nguoiTu":[{"ten":"Đoan Mộc đồng tử","tuChuong":"@c1112","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở đường","text":"Thương Tùng Tử thừa nhận cần Hồi Đại Tự Tại của Đoan Mộc để trợ giúp hành trình.","anchor":"thần thông Hồi Đại Tự Tại của Đoan Mộc đạo hữu có thể trợ giúp rất nhiều đến hành trình của chúng ta"}]}},{"id":"hoi-thuat","name":"Hồi thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Đoan Mộc đồng tử"],"blurb":"Thần thông Đoan Mộc dùng để ảnh hưởng Giao Long hóa sương trong thời gian ngắn.","detail":"Hồi thuật chỉ ảnh hưởng Giao Long hóa sương trong khoảng mười lần hít thở, tạo cơ hội cho các tu sĩ khác đồng loạt ra tay.","nguon":["@c1112"],"congNang":["Khống chế hoặc ảnh hưởng mục tiêu trong khoảng mười lần hít thở @c1112"],"nguoiTu":[{"ten":"Đoan Mộc đồng tử","tuChuong":"@c1112","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"thi triển","importance":"normal","giaiDoan":"Khống chế Giao Long","text":"Đoan Mộc dùng Hồi thuật để ảnh hưởng Giao Long hóa sương trong mười nhịp thở.","anchor":"Hồi thuật của ta chỉ ảnh hưởng đến con thú này trong khoảng thời gian mười lần hít thở"}]}},{"id":"hoi-phong-an","name":"Hồi Phong Ấn","cn":"","loai":"than-thong","loaiLabel":"Đạo cảnh phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":["Đoan Mộc đồng tử"],"blurb":"Đạo cảnh phong ấn của Đoan Mộc đồng tử dùng để kiềm chế Giao Long hóa sương.","detail":"Hồi Phong Ấn trói buộc Giao Long trong lúc bị vây công, khiến con thú gầm giận muốn thoát khỏi đạo cảnh này.","nguon":["@c1112"],"congNang":["Phong ấn và kiềm chế mãnh thú trong trận chiến @c1112"],"nguoiTu":[{"ten":"Đoan Mộc đồng tử","tuChuong":"@c1112","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"thi triển","importance":"normal","giaiDoan":"Kiềm chế Giao Long","text":"Hồi Phong Ấn được Đoan Mộc tạo ra để trói buộc Giao Long hóa sương trong trận vây công.","anchor":"Giao Long gầm lên giận dữ muốn thoát khỏi đạo cảnh Hồi Phong Ấn của Đoan Mộc"}]}},{"id":"cam-che-co-trong-the-gioi-bay-mau","name":"Cấm chế cổ trong thế giới bảy màu","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Hệ cấm chế cổ tồn tại trong thế giới bảy màu, phần lớn đã hư hỏng nhưng uy lực còn lại vẫn rất mạnh.","detail":"Vương Lâm nhận ra nhiều cấm chế nơi đây tuy đã tan vỡ quá nửa nhưng phần còn vận chuyển vẫn vượt xa cấm chế trong động phủ Thanh Lâm, cho thấy lai lịch thế giới bảy màu rất sâu.","nguon":["@c1112"],"uyLuc":"Phần còn vận chuyển mạnh hơn rất nhiều so với cấm chế trong Thanh Lâm động phủ.","dacDiem":"Đã hư hỏng quá nửa nhưng vẫn khiến nơi này cực kỳ nguy hiểm.","congNang":["Ngăn cản người ngoài tiến sâu vào thế giới bảy màu bằng uy lực cấm chế cổ @c1112"],"capNhatToi":"@c1112","tabs":{"tienTrinh":[{"chuong":"@c1112","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm nhận ra","text":"Vương Lâm phát hiện cấm chế cổ trong thế giới bảy màu tuy hư hỏng nhưng uy lực còn lại vẫn vượt cấm chế Thanh Lâm động phủ.","anchor":"uy lực của những cấm chế này thậm chí còn mạnh hơn rất nhiều so với cấm chế trong Thanh Lâm động phủ"}]}},{"id":"phong-an-nhat-nguyet-cua-doan-moc","name":"Phong ấn nhật nguyệt của Đoan Mộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông phong ấn","phamCap":"","hePhai":"","soHuu":["Đoan Mộc"],"blurb":"Phong ấn dùng dấu ấn nhật nguyệt để hạn chế thân thể Giao Long trong trận vây công tại thế giới bảy màu.","detail":"Đoan Mộc thi triển dấu ấn nhật nguyệt đặt lên đầu Giao Long, tạm thời khống chế mãnh thú để các tu sĩ khác dùng phi kiếm, lô cầu, kiếm vũ và huyền băng công kích. Khi Giao Long giãy dụa dữ dội, Đoan Mộc chịu phản chấn đến thổ huyết; lúc dấu ấn tan vỡ, Giao Long thoát khỏi hạn chế.","nguon":["@c1113"]},{"id":"kiem-vu-hon-mot-van-phi-kiem-cua-thuong-tung-tu","name":"Kiếm vũ hơn một vạn phi kiếm của Thương Tùng Tử","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"","hePhai":"","soHuu":["Thương Tùng Tử"],"blurb":"Kiếm trận quy mô lớn do Thương Tùng Tử điều khiển, gọi hơn một vạn phi kiếm như mưa đánh xuống Giao Long.","detail":"Trong lúc Đoan Mộc còn duy trì phong ấn, Thương Tùng Tử bấm quyết khiến hơn một vạn phi kiếm phóng tới như mưa, dồn lực công kích lên thân thể Giao Long. Chiêu này phối hợp với các đòn đánh khác để tăng áp lực lên mãnh thú trước khi phong ấn nhật nguyệt sụp đổ.","nguon":["@c1113"]},{"id":"huyen-bang-cua-lao-ba-ao-xanh","name":"Huyền băng của lão bà áo xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Lão bà áo xanh"],"blurb":"Thần thông huyền băng bao phủ Giao Long, vừa đóng băng tạm thời vừa hấp thu hắc khí và sinh cơ của mãnh thú.","detail":"Lão bà áo xanh dùng huyền băng phủ lên toàn thân Giao Long, khiến mãnh thú tạm ngừng giãy dụa và bị hấp thu sinh cơ. Khi Giao Long phá phong ấn, lớp băng bị thân thể nó phá vỡ rồi quay về quanh lão bà; sau trận, bà tiếp tục hút hắc khí và huyết khí từ thi thể Giao Long.","nguon":["@c1113"]},{"id":"luoi-dien-hac-quang-cua-sung-giao-long","name":"Lưới điện hắc quang của sừng Giao Long","cn":"","loai":"than-thong","loaiLabel":"Thần thông yêu thú","phamCap":"","hePhai":"","soHuu":["Giao Long hóa sương cấp mười hai"],"blurb":"Thần thông từ chiếc sừng đen của Giao Long, tạo lưới điện màu đen và nhiều hư ảnh Giao Long để uy hiếp đối thủ.","detail":"Khi Giao Long sắp thăng không, chiếc sừng đen trên đầu nó phát sáng, hút nguyên lực thiên địa cùng ánh sáng bảy màu rồi tỏa ra lưới điện đen như chớp. Sức mạnh này còn huyễn hóa hàng loạt hư ảnh Giao Long, khiến nhóm tu sĩ phải khẩn cấp ứng phó.","nguon":["@c1113"]},{"id":"than-thong-cua-tran-thien-quan-dich-thu-tong","name":"Thần thông của Trần Thiên Quân Dịch Thú Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Dịch Thú Tông","soHuu":["Trần Thiên Quân"],"blurb":"Thần thông của Trần Thiên Quân thuộc Dịch Thú Tông, được nhận ra qua dao động nguyên lực truyền tới từ xa trong thế giới bảy màu.","detail":"Dao động của thần thông này tạo nên những làn sóng nguyên lực có ẩn cảm giác chấn động nguyên thần, khiến Thương Tùng Tử lập tức nhận ra là thủ đoạn của Trần Thiên Quân.","congNang":["Gây dao động nguyên lực và chấn động nguyên thần từ xa @c1115"],"uyLuc":"Dao động lan tới mức làm nguyên thần người trong đoàn cảm thấy chấn động.","dacDiem":"Dấu hiệu nhận biết gắn với Trần Thiên Quân của Dịch Thú Tông.","nguoiTu":[{"ten":"Trần Thiên Quân","tuChuong":"@c1115","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"nhắc tới","importance":"normal","giaiDoan":"Dao động từ xa","text":"Dao động thần thông truyền tới trong thế giới bảy màu và được Thương Tùng Tử nhận ra là của Trần Thiên Quân thuộc Dịch Thú Tông.","anchor":"Trong những con sóng nguyên lực dao động này có ẩn giấu một luồng cảm giác chấn động nguyên thần"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"cuu-bo-phong-tien-tran","name":"Cửu Bộ Phong Tiên Trận","aliases":["Cửu Bộ Phong Thiên Trận"],"cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"Thượng cổ kỳ trận","hePhai":"Không rõ","soHuu":[],"blurb":"Cửu Bộ Phong Tiên Trận là một thượng cổ kỳ trận phong bế đường xuyên núi trong thế giới bảy màu. Trận đã tổn hại nhiều chỗ và mất lực công kích, nhưng phong ấn vẫn hoàn thiện và cực kỳ hiệu quả.","detail":"Cửu Bộ Phong Tiên Trận là thượng cổ kỳ trận, được Triệu lão bà nhận ra khi xuất hiện tại vách núi ở cuối con đường hẹp, dùng để phong bế thạch động xuyên núi trong thế giới bảy màu @c1115. Dù trận pháp đã có nhiều chỗ tổn hại và không còn lực công kích, phong ấn vẫn giữ nguyên độ hoàn thiện. Muốn phá trận phải tiến đủ mười bước dưới áp lực phong ấn; Triệu lão bà tinh thông cấm chế chỉ chống đỡ được đến bước thứ sáu, còn Thương Tùng Tử dù mặc Thần Ma Giáp vẫn bị đánh bật ở bước thứ chín.","nguonGoc":"Thượng cổ kỳ trận","congNang":["Phong ấn cửa đường xuyên núi trong thế giới bảy màu @c1115","Buộc người phá trận phải tiến đủ mười bước mới có thể phá @c1115"],"uyLuc":"Có thể đánh bật cả Triệu lão bà tinh thông cấm chế lẫn Thương Tùng Tử mặc Thần Ma Giáp trước khi họ đi đủ mười bước.","dacDiem":"Trận pháp đã tổn hại nhiều chỗ, không còn lực công kích nhưng phong ấn vẫn hoàn thiện.","trangThai":"đang phong ấn đường xuyên núi","tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện trong vách núi","text":"Cửu Bộ Phong Tiên Trận được Triệu lão bà nhận ra là thượng cổ kỳ trận phong bế thạch động xuyên núi. Trận đã tổn hại nhưng phong ấn vẫn hoàn thiện, cần tiến đủ mười bước để phá.","anchor":"Trận pháp này đã trải qua rất nhiều năm tháng, đã có nhiều chổ tổn hại, đã không còn lực công kích nhưng phong ấn lại quá hiệu quả"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"thu-an-cam-che-cua-trieu-lao-ba","name":"Thủ ấn cấm chế của Triệu lão bà","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế pháp quyết","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Bà lão áo xanh"],"blurb":"Thủ pháp cấm chế do Triệu lão bà áo xanh thi triển trước vách núi.","detail":"Bà dùng hai tay bấm pháp quyết, khiến nhiều thủ ấn chồng lên nhau thành ký hiệu cấm chế phức tạp rơi vào vách núi, làm mặt đá rung động và lộ ra dấu hiệu cửa động.","congNang":["Kích động cấm chế trên vách núi và làm lộ cửa thạch động @c1115"],"dacDiem":"Các thủ ấn chồng chất thành một ký hiệu cấm chế cực kỳ phức tạp.","nguoiTu":[{"ten":"Bà lão áo xanh","tuChuong":"@c1115","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"thi triển","importance":"normal","giaiDoan":"Mở dấu vách núi","text":"Triệu lão bà dùng thủ ấn cấm chế đánh vào vách núi, khiến núi đá rung động và lộ ra cửa thạch động.","anchor":"Những thủ ấn này chồng chất lên nhau tạo thành một ký hiệu cấm chế cực kỳ phức tạp"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"thu-doan-bay-luong-hac-khi-cua-trieu-lao-ba","name":"Thủ đoạn bảy luồng hắc khí của Triệu lão bà","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật cấm chế phụ trợ","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Bà lão áo xanh"],"blurb":"Bí thuật phụ trợ Triệu lão bà dùng khi tiến vào Cửu Bộ Phong Tiên Trận.","detail":"Bà phóng bảy luồng hắc khí từ thất khiếu, trong hắc khí ẩn chứa sinh cơ, rồi bước vào núi đá để chống đỡ áp lực của trận pháp.","congNang":["Trợ lực cho người thi triển khi nhập trận @c1115"],"dacDiem":"Bảy luồng hắc khí bùng ra từ thất khiếu và chứa sinh cơ.","nguoiTu":[{"ten":"Bà lão áo xanh","tuChuong":"@c1115","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"thi triển","importance":"normal","giaiDoan":"Nhập trận","text":"Triệu lão bà phóng bảy luồng hắc khí từ thất khiếu khi thử tiến vào Cửu Bộ Phong Tiên Trận.","anchor":"Đột nhiên có bảy luồng hắc khí từ trên thất khiếu lão bà áo xanh bùng ra ngoài"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"y-canh-than-thong-cua-doan-moc-dao-huu","name":"Ý cảnh thần thông của Đoan Mộc đạo hữu","cn":"","loai":"than-thong","loaiLabel":"Ý cảnh thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Đoan Mộc đồng tử"],"blurb":"Ý cảnh thần thông của Đoan Mộc đồng tử được nhắc là có thể hỗ trợ phá biến hóa cấm chế.","detail":"Thương Tùng Tử cho rằng nếu Đoan Mộc còn ở đây thì ý cảnh thần thông của hắn có thể phong ấn sự biến hóa của cấm chế, giúp Triệu lão bà phá trận.","congNang":["Phong ấn sự biến hóa của cấm chế @c1115"],"nguoiTu":[{"ten":"Đoan Mộc đồng tử","tuChuong":"@c1115","tangDatToi":"","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1115","loai":"nhắc tới","importance":"normal","giaiDoan":"Trợ lực vắng mặt","text":"Thương Tùng Tử nhắc rằng ý cảnh thần thông của Đoan Mộc có thể phong ấn biến hóa cấm chế, nhưng Đoan Mộc đã bị Mê Thất Giả mang đi.","anchor":"nếu không dùng ý cảnh thần thông của hắn nhất định sẽ có thể phong ấn được sự biến hóa của cấm chế"}]},"capNhatToi":"@c1115","nguon":["@c1115"]},{"id":"cam-che-vo-hinh-cua-vuong-lam","name":"Cấm chế vô hình của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế vô hình được Vương Lâm âm thầm đưa vào trận pháp trong lúc bước vào vách đá.","detail":"Khi mọi người bị dao động của vách đá che mắt, Vương Lâm để luồng cấm chế vô hình từ tay phải dung nhập vào Cửu Bộ Phong Tiên Trận. Thủ đoạn này phục vụ việc phá trận và che giấu ý đồ thật của hắn.","thuocTinh":"cấm chế","nguonGoc":"Vương Lâm thi triển","congNang":["Dung nhập vào trận pháp trong lúc người ngoài khó phát giác @c1116"],"uyLuc":"Có thể can thiệp vào Cửu Bộ Phong Tiên Trận trong quá trình Vương Lâm vượt trận.","dacDiem":"Vô hình, được đưa vào trận pháp giữa dao động của vách đá.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1116","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1116","loai":"xuất hiện","importance":"normal","giaiDoan":"Dung nhập trận pháp","text":"Vương Lâm âm thầm đưa cấm chế vô hình vào Cửu Bộ Phong Tiên Trận khi bước vào vách đá.","anchor":"lợi dụng khoảnh khắc những con sóng rung động vang vọng để một luồng cấm chế vô hình trên tay phải dung nhập vào trong trận pháp"}]},"capNhatToi":"@c1116","nguon":["@c1116"]},{"id":"than-thong-tim-kiem-ky-uc","name":"Thần thông tìm kiếm ký ức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng để cưỡng ép tra xét ký ức nguyên thần sau khi đối phương suy yếu.","detail":"Vương Lâm thi triển lên nguyên thần lão già họ Bàng để lấy tin tức về Thương Tùng Tử, động phủ Tư Mã Mặc và thế giới bảy màu.","thuocTinh":"搜 ký ức nguyên thần","uyLuc":"Có thể lấy tin tức từ nguyên thần đã bị ép vào trạng thái suy yếu.","dacDiem":"Được dùng sau khi thân thể lão Bàng bị phá và nguyên thần bị chém suy yếu.","congNang":["Tra xét ký ức nguyên thần suy yếu để thu tin tức về người, địa điểm và kế hoạch liên quan @c1117"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1117","tangDatToi":"đã thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"thi triển","importance":"normal","giaiDoan":"Tra ký ức lão Bàng","text":"Vương Lâm dùng thần thông này lên nguyên thần suy yếu của lão Bàng để lấy tin tức cần thiết.","anchor":"Sau khi cưỡng ép nguyên thần đối phương rơi xuống trạng thái suy yếu thì Vương Lâm lập tức thi triển thần thông tìm kiếm ký ức."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"cam-che-pha-phong-an-nhan","name":"Cấm chế phá phong ấn nhẫn","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế được Vương Lâm dùng để phá tầng phong ấn trên chiếc nhẫn chín tầng.","detail":"Dựa vào trình độ cấm chế của mình, Vương Lâm bấm pháp quyết, gọi cấm chế rơi lên chiếc nhẫn và phá tiếp tầng phong ấn thứ tám.","thuocTinh":"cấm chế phá phong ấn","uyLuc":"Phá được tầng phong ấn thứ tám còn lại trên chiếc nhẫn của lão Bàng.","dacDiem":"Gắn với thao tác bấm pháp quyết và rơi cấm chế lên pháp bảo.","congNang":["Phá phong ấn pháp bảo, cụ thể là tầng thứ tám trên chiếc nhẫn chín tầng @c1117"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1117","tangDatToi":"đã thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1117","loai":"thi triển","importance":"normal","giaiDoan":"Phá phong ấn nhẫn","text":"Vương Lâm dùng cấm chế để phá nốt tầng phong ấn thứ tám trên chiếc nhẫn.","anchor":"Tay trái Vương Lâm bấm pháp quyết, cấm chế lập tức xuất hiện rồi rơi trên chiếc nhẫn."}]},"capNhatToi":"@c1117","nguon":["@c1117"]},{"id":"sinh-tu-cam","name":"Sinh Tử Cấm","cn":"生死禁","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Một trong Tứ Đại Cấm Thuật","hePhai":"Tứ Đại Cấm Thuật","soHuu":["Lão bà áo xanh","Vương Lâm"],"blurb":"Sinh Tử Cấm là một trong Tứ Đại Cấm Thuật thời thượng cổ. Vương Lâm nhận ra dấu vết của nó qua cách trận trong sơn cốc hút sinh cơ vạn linh làm Tử Cấm. (+) Cấm chế ẩn trong sương đỏ, giết người bằng cách khiến mặt và nguyên thần lộ nụ cười quỷ dị không thể kiểm soát, dẫn đến tử vong. [CAN-SOAT-GOP] (+) Một trong tứ đại cấm chế trên chiến thuyền Phàn San Lộ, được Vương Lâm nhận diện. [CAN-SOAT-GOP]","detail":"Trong Mai Hoa Thập Bát Cấm ở sơn cốc, Vương Lâm phát hiện hắc quang trung tâm và kiểm tra cỏ cây đã hư thối vì sinh cơ bị hút. Từ đó hắn nhận ra phương pháp của lão bà áo xanh có nét tương tự Sinh Tử Cấm, rồi dùng Phá Diệt Tâm Cấm để dung hợp thành phản bẫy.","thuocTinh":"Sinh tử, cấm chế","nguonGoc":"Một nhánh của Tứ Đại Cấm Thuật thời thượng cổ.","dacDiem":"Có thể dùng sinh cơ vạn linh làm Tử Cấm trong trận pháp.","congNang":["Hút sinh cơ vạn linh để hình thành Tử Cấm trong cấm trận @c1118","Chưa rõ công dụng cụ thể, được coi là vật quý giá đủ đổi mạng"],"tabs":{"tienTrinh":[{"chuong":"@c1118","loai":"xuất hiện","importance":"normal","giaiDoan":"Dấu vết trong trận sơn cốc","text":"Vương Lâm nhận ra trận của lão bà áo xanh dùng sinh cơ vạn linh làm Tử Cấm, có nét tương tự Sinh Tử Cấm trong Tứ Đại Cấm thời thượng cổ.","anchor":"phương pháp này có chút tương tự Sinh Tử Cấm trong Tứ Đại Cấm thời thượng cổ"},{"chuong":"@c1159","loai":"đổi chủ","importance":"normal","giaiDoan":"Lão phụ nhân áo xanh dâng cho Vương Lâm","text":"Lão phụ nhân áo xanh dâng Sinh Tử Cấm đổi mạng sống. Vương Lâm lục soát thiên linh lấy được cấm chế rồi thả bà ta đi.","anchor":"lão thân nguyện ý dâng ra Sinh Tử Cấm, đổi lấy một cơ hội sống"}]},"capNhatToi":"@c1118","nguon":["@c1118","@c1159","@c1356","@c1599"],"chuSoHuu":[{"ten":"Lão phụ nhân áo xanh","tuChuong":"@c1159","denChuong":"@c1159","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1159","denChuong":"","cachCoDuoc":"Lục soát thiên linh lão phụ nhân áo xanh","trangThai":"dang-co"}]},{"id":"dao-kinh","name":"Đạo Kinh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đạo kinh","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đạo Kinh là vật được Thương Tùng Tử tiết lộ trong vùng sương mù của thế giới bảy màu. Minh Chí Giả là những kẻ có đạo cảnh nhưng không có Đạo Kinh nên còn chấp niệm đạo hồn truy tìm.","detail":"Thương Tùng Tử nói sau khi vào thế giới bảy màu mới biết trong thiên địa này có một bộ Đạo Kinh. Vật này nghe nói do máu huyết thiên địa tạo thành, trở thành then chốt khiến Minh Chí Giả không ngừng truy tìm sau nhiều vạn năm.","nguonGoc":"Nghe nói do máu huyết thiên địa tạo thành.","dacDiem":"Liên hệ với đạo cảnh và chấp niệm đạo hồn của Minh Chí Giả.","congNang":["Là thứ mà những kẻ có đạo cảnh nhưng không có Đạo Kinh như Minh Chí Giả truy tìm @c1118"],"tabs":{"tienTrinh":[{"chuong":"@c1118","loai":"xuất hiện","importance":"major","giaiDoan":"Bí mật trong sương mù","text":"Thương Tùng Tử hé lộ trong thiên địa này có một bộ Đạo Kinh, nghe nói do máu huyết thiên địa tạo thành và là thứ Minh Chí Giả truy tìm.","anchor":"biết được trong thiên địa này có một bộ Đạo Kinh"}]},"capNhatToi":"@c1118","nguon":["@c1118"]},{"id":"tue-nguyet-cam","name":"Tuế Nguyệt Cấm","cn":"岁月禁","aliases":[],"loai":"than-thong","loaiLabel":"Cấm chế","phamCap":"chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tuế Nguyệt Cấm là phong ấn cấm chế màu đen bao quanh ngọn núi nhỏ chìm trong sương mù, hấp thu lực lượng quy tắc thời gian nên tồn tại càng lâu uy lực càng mạnh. Về sau Vương Lâm đạt được Tuế Nguyệt Cấm chế trong Thất Thải giới. (+) Một trong tam đại cấm chế, uy lực chính là thao túng thời gian. Vương Lâm nghiên cứu sau khi rời thế giới bảy màu, kết hợp thần thông Lưu Nguyệt nghịch chuyển để thi triển. [CAN-SOAT-GOP] (+) Cấm chế gắn với lực năm tháng của Tư Mặc Tử, có thể hoang hóa thiên địa và cuốn lực hủy diệt vào đối thủ. Trong chương này nó bị lôi đồ vạn trượng của Vương Lâm phá tan. [CAN-SOAT-GOP] (+) Loại cấm chế thứ hai trên sương đỏ trên lưng Cổ Thần, kết hợp với Cổ Hồn cấm tạo uy lực kinh thiên. [CAN-SOAT-GOP] (+) Một trong tứ đại cấm chế trên chiến thuyền Phàn San Lộ, được Vương Lâm nhận diện. [CAN-SOAT-GOP] (+) Cấm chế Vương Lâm lưu lại trong động phủ để phán đoán thời gian mình rời đi. [CAN-SOAT-GOP]","detail":"Cấm chế này được lão bà áo xanh họ Triệu nhận ra là phong ấn hấp thu quy tắc thời gian, khiến uy lực gia tăng theo thời gian tồn tại (@c1119). Nó bao bọc ngọn núi và về sau lộ ra bao quanh hai ngọn núi bí mật trong sương mù dày đặc (@c1130), ngăn người ngoài xâm nhập, phong ấn lâu dài và tự khôi phục các khe nứt (@c1120). Màn cấm chế không bị phá hoàn toàn, chỉ bị mở lỗ hổng sau khi Thứ Không Niết Bảo thật tự hủy; Vương Lâm lợi dụng vết nứt chưa liền, dùng Phá Diệt Cấm cùng Thủy Tinh Kiếm và Tam Xoa Kích để xé toạc cấm chế (@c1136). Về sau Vương Lâm hồi tưởng đã đạt được Tuế Nguyệt Cấm chế trong Thất Thải giới (@c1159).","thuocTinh":"thời gian, phong ấn, cấm chế","uyLuc":"Hấp thu quy tắc thời gian nên càng tồn tại lâu càng mạnh, cấm chế không bị phá hoàn toàn mà chỉ bị mở lỗ hổng sau khi Thứ Không Niết Bảo thật tự hủy.","dacDiem":"Màn cấm chế màu đen không bị phá hoàn toàn, chỉ bị mở lỗ hổng sau khi Thứ Không Niết Bảo thật tự hủy, và có khả năng tự khôi phục khe nứt.","congNang":["Hấp thu lực lượng quy tắc thời gian, khiến phong ấn càng tồn tại lâu càng mạnh @c119","Bao bọc ngọn núi nhỏ và ngăn người ngoài tiến vào vùng phong ấn @c1119","Phong ấn lâu dài và tự khôi phục các khe nứt @c120","Bao quanh hai ngọn núi bí mật trong sương mù dày đặc @c1130"],"trangThai":"đang vận hành","capNhatToi":"@c1119","tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ phong ấn","text":"Tuế Nguyệt Cấm được lão bà áo xanh nhận ra là phong ấn hấp thu quy tắc thời gian và chỉ bị mở lỗ hổng sau khi nhiều bảo vật bị tự hủy.","anchor":"hấp thu lực lượng của quy tắc thời gian"},{"chuong":"@c1120","loai":"xuất hiện","importance":"normal","giaiDoan":"Khe nứt sắp khép","text":"Khe nứt trên Tuế Nguyệt Cấm đang nhanh chóng khép lại, buộc người bên trong phải tranh thủ thời gian trước khi phong ấn hồi phục hoàn toàn.","anchor":"nếu không dùng rất nhiều bảo vật để đánh vỡ ra thì phong ấn Tuế Nguyệt Cấm này sẽ tồn tại mãi mãi"},{"chuong":"@c1130","loai":"xuất hiện","importance":"normal","giaiDoan":"Được phát hiện bởi tâm thần Vương Lâm","text":"Tâm thần Vương Lâm tiến vào sương mù dày đặc, nhìn thấy Tuế Nguyệt Cấm bao quanh hai ngọn núi bí mật và xuyên qua không bị ngăn cản.","anchor":"Tuế Nguyệt Cấm cũng không thể ngăn cản được tâm thần Vương Lâm"},{"chuong":"@c1136","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Vương Lâm phá vỡ","text":"Vương Lâm lợi dụng sơ hở vết nứt chưa liền, dùng Phá Diệt Cấm + Thủy Tinh Kiếm + Tam Xoa Kích xé toạc cấm chế tiến vào.","anchor":"Đây cũng là một sơ hở tai hại của Tuế Nguyệt Cấm!"},{"chuong":"@c1159","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm đạt được trong Thất Thải giới","text":"Vương Lâm hồi tưởng đã đạt được Tuế Nguyệt Cấm chế trong Thất Thải giới.","anchor":"Đạt được Tuế Nguyệt Cấm chế"}]},"nguon":["@c1119","@c1120","@c1130","@c1136","@c1159","@c1201","@c1292","@c1355","@c1599","@c1834"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1159","tangDatToi":"Không rõ","trangThai":"dang-tu"}]},{"id":"thuat-cam-che-cua-lao-ba-ao-xanh-ho-trieu","name":"Thuật cấm chế của lão bà áo xanh họ Triệu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Cấm chế thuật","phamCap":"chưa rõ","hePhai":"","soHuu":["Bà lão áo xanh"],"blurb":"Thuật cấm chế của lão bà áo xanh họ Triệu được Thương Tùng Tử đánh giá cao hơn năng lực cấm chế của chính lão.","detail":"Bà dùng pháp quyết, hắc khí, máu tươi và ký hiệu cấm chế để dung hợp vào Phá Cấm Trùy, rồi điều khiển sức nổ của khối gỗ đen, tinh thạch và ngọc bội Thứ Không Niết Bảo đánh xuống Tuế Nguyệt Cấm.","nguoiTu":[{"ten":"Bà lão áo xanh","tuChuong":"@c1119","tangDatToi":"chưa rõ","trangThai":"đang dùng"}],"congNang":["Dung hợp hắc khí, cấm chế và máu tươi vào Phá Cấm Trùy để công kích màn cấm @c1119","Điều khiển lực nổ của bảo vật tự hủy đánh vào Tuế Nguyệt Cấm @c1119"],"uyLuc":"Có thể phối hợp nhiều bảo vật quý để mở lỗ hổng trên Tuế Nguyệt Cấm.","dacDiem":"Khi vận dụng tới mức cao, hình dạng người thi triển biến đổi từ lão bà thành phụ nữ trung niên rồi cô gái trẻ.","capNhatToi":"@c1119","tabs":{"tienTrinh":[{"chuong":"@c1119","loai":"thi triển","importance":"normal","giaiDoan":"Phá Tuế Nguyệt Cấm","text":"Lão bà áo xanh vận dụng thuật cấm chế phối hợp Phá Cấm Trùy, hắc khí, máu tươi và pháp bảo tự hủy để phá màn cấm chế.","anchor":"thần thông của lão phu trên phương diện cấm chế không thể so sánh với ngươi"}]},"nguon":["@c1119"]},{"id":"cam-che-ngoai-dong-phu-cua-co-gai-ao-xanh","name":"Cấm chế ngoài động phủ của cô gái áo xanh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"","soHuu":["Bà lão áo xanh"],"blurb":"Cấm chế do cô gái áo xanh họ Triệu bố trí ngoài cửa động phủ thú hồn trước khi bước vào. Đây là lớp phòng bị của nàng khi còn nghi ngờ Thương Tùng Tử.","detail":"Trước khi vào động phủ phong ấn thú hồn, cô gái áo xanh để lại vài cấm chế bên ngoài. Thương Tùng Tử sau đó khép cửa đá nhốt nàng và cho rằng các cấm chế bên ngoài không ảnh hưởng tới mục tiêu thật của mình.","congNang":["Bố trí phòng bị ngoài cửa động phủ @c1120"],"trangThai":"đã bố trí","capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"xuất hiện","importance":"normal","giaiDoan":"Phòng bị trước khi vào động phủ","text":"Cô gái áo xanh bố trí vài cấm chế ngoài cửa rồi mới bước vào động phủ thú hồn.","anchor":"Sau khi để lại vài cấm chế bên ngoài, cô gái áo xanh lập tức cất bước đi vào"}]},"nguon":["@c1120"]},{"id":"tran-phap-nguc-tu-duoi-hai-cot","name":"Trận pháp ngục tù dưới hài cốt","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp hình tròn đặt dưới nửa bộ hài cốt màu đen trong không gian tấm bia. Bình ngọc nằm ở trung tâm trận pháp, ngay dưới xương sống hài cốt.","detail":"Trận pháp có nhiều ký hiệu ngục tù, giữ bình ngọc dưới bộ hài cốt. Thương Tùng Tử phải dùng máu và bốn tiểu kiếm kim quang cắm quanh trận pháp mới nhấc được bình ngọc lên.","congNang":["Trấn giữ bình ngọc dưới hài cốt @c1120"],"trangThai":"bị Thương Tùng Tử phá để lấy bình ngọc","capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"xuất hiện","importance":"normal","giaiDoan":"Trấn giữ bình ngọc","text":"Trận pháp hình tròn dưới bộ hài cốt giữ bình ngọc ở vị trí trung tâm và bị Thương Tùng Tử dùng thủ đoạn phá mở.","anchor":"Phía dưới bộ hài cốt có một trận pháp hình tròn rộng khoảng vài trượng"}]},"nguon":["@c1120"]},{"id":"duong-tu-am-quy","name":"Dương Tụ Âm Quy","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Cấm thuật tổ thuật","phamCap":"không rõ","hePhai":"","soHuu":["Bà lão áo xanh","Người phụ nữ trung niên áo xanh họ Triệu","Bà lão áo xanh họ Triệu"],"blurb":"Dương Tụ Âm Quy là cấm thuật tổ thuật của nữ tu họ Triệu, khiến mẹ con nhiều đời cùng chung một thân thể. Thương Tùng Tử nhận ra thuật này khi hai nữ tu họ Triệu dung mạo giống nhau cùng xuất hiện, không phải phân thân mà là biểu hiện của cấm thuật.","detail":"Dương Tụ Âm Quy không phải phân thân mà là cấm thuật khiến mẹ con nhiều đời đồng tồn trong một thân thể, nhờ đó tu vi tăng mạnh và thần thức cực kỳ hùng mạnh. Tính tới mốc @c1120, thuật đã đạt cảnh giới ba đời, thể hiện qua sự xuất hiện của người phụ nữ trung niên và bà lão áo xanh họ Triệu.","congNang":["Khiến mẹ con nhiều đời cùng chung một thân thể, tăng mạnh tu vi và thần thức @c1120"],"trangThai":"đã lộ","capNhatToi":"@c1120","tabs":{"tienTrinh":[{"chuong":"@c1120","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ cấm thuật ba đời","text":"Thương Tùng Tử nhận ra hai nữ tu họ Triệu dung mạo giống nhau không phải phân thân mà là Dương Tụ Âm Quy.","anchor":"Đây không phải là phân thân, chính là tổ thuật Dương Tụ Âm Quy"}]},"nguon":["@c1120"],"dacDiem":"Cấm thuật tổ thuật của nữ tu họ Triệu, không phải phân thân mà khiến mẹ con nhiều đời đồng tồn trong một thân thể; các đời có dung mạo giống nhau."},{"id":"tu-am-quy-co-thuat","name":"Tụ Âm Quy Cổ Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Một cổ thuật khiến Thương Tùng Tử vẫn còn khiếp sợ trong lúc giao chiến.","detail":"Chương này chỉ nhắc Tụ Âm Quy Cổ Thuật qua tâm trạng kiêng dè của Thương Tùng Tử, chưa mô tả trực tiếp cách thi triển hay nguồn gốc.","nguon":["@c1121"],"congNang":["Gây uy hiếp tâm lý khiến Thương Tùng Tử vẫn còn khiếp sợ @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"nhắc tới","importance":"bridge","giaiDoan":"Được nhắc trong lúc Thương Tùng Tử chuẩn bị phá vây","text":"Thương Tùng Tử vẫn còn khiếp sợ Tụ Âm Quy Cổ Thuật nhưng tiếp tục hành động.","anchor":"Tuy trong lòng vẫn còn khiếp sợ Tụ Âm Quy Cổ Thuật"}]},"capNhatToi":"@c1121"},{"id":"luc-hut-doat-sinh-co-cua-lao-ba-ao-xanh","name":"Lực hút đoạt sinh cơ của lão bà áo xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Lão bà áo xanh"],"blurb":"Thần thông lão bà áo xanh dùng để kéo sinh cơ của Thương Tùng Tử trong màn giao chiến.","detail":"Lão bà áo xanh bấm niệm pháp quyết rồi khẽ hút, tạo lực hút khiến Thương Tùng Tử cảm giác sinh cơ trong thân thể bị kéo đi.","nguon":["@c1121"],"congNang":["Tạo lực hút kéo sinh cơ của mục tiêu @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"thi triển","importance":"normal","giaiDoan":"Mở màn giao chiến","text":"Lão bà áo xanh dùng lực hút khiến Thương Tùng Tử cảm thấy sinh cơ bị kéo đi.","anchor":"Thân thể Thương Tùng Tử đứng trong lực hút thì lập tức sinh ra cảm giác giống như sinh cơ hoàn toàn bị kéo đi."}]},"capNhatToi":"@c1121"},{"id":"kim-quang-hoa-van-phi-kiem","name":"Kim quang hóa vạn phi kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thương Tùng Tử"],"blurb":"Thần thông của Thương Tùng Tử dùng kim quang huyễn hóa hàng vạn phi kiếm để công kích.","detail":"Thương Tùng Tử vung trảo làm kim quang xuất hiện, từ đó huyễn hóa hàng vạn phi kiếm tạo thành thế công quy mô lớn nhằm vào lão bà áo xanh.","nguon":["@c1121"],"congNang":["Huyễn hóa hàng vạn phi kiếm từ kim quang để tấn công diện rộng @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"thi triển","importance":"normal","giaiDoan":"Phản công lão bà áo xanh","text":"Thương Tùng Tử dùng kim quang huyễn hóa hàng vạn phi kiếm để đánh lão bà áo xanh.","anchor":"Sau khi kim quang xuất hiện thì huyễn hóa ra hàng vạn phi kiếm"}]},"capNhatToi":"@c1121"},{"id":"bay-thanh-truong-kiem-mau-sac-khac-nhau","name":"Bảy thanh trường kiếm màu sắc khác nhau","cn":"","loai":"than-thong","loaiLabel":"Thần chú thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thương Tùng Tử"],"blurb":"Thần chú của Thương Tùng Tử biến luồng sáng bảy màu thành bảy thanh trường kiếm.","detail":"Khi truy chạy về phía tấm màn cấm chế, Thương Tùng Tử đọc thần chú khiến luồng sáng bảy màu hóa thành bảy thanh trường kiếm màu sắc khác nhau để công kích lão phụ nhân áo xanh.","nguon":["@c1121"],"congNang":["Dùng ánh sáng bảy màu hóa thành bảy trường kiếm công kích @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu lão phụ nhân áo xanh","text":"Thương Tùng Tử dùng thần chú biến luồng sáng bảy màu thành bảy thanh trường kiếm.","anchor":"sau đó lại hóa thành bảy thanh trường kiếm màu sắc khác nhau"}]},"capNhatToi":"@c1121"},{"id":"sinh-sinh-tu","name":"Sinh sinh tử","cn":"","loai":"than-thong","loaiLabel":"Cấm chế thần niệm","phamCap":"Không rõ","hePhai":"","soHuu":["Lão phụ nhân áo xanh"],"blurb":"Chiêu thức dung hợp ba luồng Sinh Tử Cấm của lão phụ nhân áo xanh.","detail":"Lão phụ nhân áo xanh phát ra thần niệm khiến ba luồng Sinh Tử Cấm dung hợp, tạo uy lực hủy thiên diệt địa để đối kháng Nghịch Hành Giả và sau đó đánh về phía Vương Lâm.","nguon":["@c1121"],"congNang":["Dung hợp ba luồng Sinh Tử Cấm thành uy lực hủy thiên diệt địa @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng Nghịch Hành Giả","text":"Lão phụ nhân dùng Sinh sinh tử để ba luồng cấm chế dung hợp thành thế công cực mạnh.","anchor":"ba luồng cấm chế lập tức dung hợp lại rồi tạo thanhg một uy lực hủy thiên diệt địa."}]},"capNhatToi":"@c1121"},{"id":"cam-che-vuong-lam-bo-tri-ngoai-lo-hong","name":"Cấm chế Vương Lâm bố trí ngoài lỗ hổng","cn":"","loai":"than-thong","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế Vương Lâm đặt trước bên ngoài khe nứt để cản người truy đuổi.","detail":"Vương Lâm bố trí cấm chế ngoài lỗ hổng từ trước; khi Thương Tùng Tử lao ra truy kích, lão giẫm lên cấm chế này và bị khựng lại.","nguon":["@c1121"],"congNang":["Chặn bước truy đuổi của Thương Tùng Tử ngoài lỗ hổng @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"thi triển","importance":"normal","giaiDoan":"Chặn truy kích sau khi đoạt bình","text":"Cấm chế đặt sẵn ngoài lỗ hổng khiến Thương Tùng Tử khựng lại khi truy đuổi Vương Lâm.","anchor":"lại giẫm lên cấm chế trước đó Vương Lâm đã bố trí bên ngoài."}]},"capNhatToi":"@c1121"},{"id":"thien-van-nhat-chi","name":"Thiên Vận Nhất Chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thiên Vận Tử"],"blurb":"Thiên Vận Nhất Chỉ là một thần thông một chỉ khổng lồ, được Vương Lâm nhận ra là có liên quan đến Thiên Vận Tử khi nó tái hiện.","detail":"Thiên Vận Nhất Chỉ xuất hiện khi Thương Tùng Tử ném hạt châu Nghịch Hành Giả, ánh sáng bảy màu ngưng tụ thành một ngón tay khổng lồ giáng xuống mục tiêu. Vương Lâm nhận ra đó chính là Thiên Vận Nhất Chỉ và từ đó kết luận nơi này có liên quan đến Thiên Vận Tử.","nguon":["@c1121"],"nguonGoc":"Liên quan Thiên Vận Tử","congNang":["Ánh sáng bảy màu ngưng tụ thành ngón tay khổng lồ giáng xuống mục tiêu @c1121"],"tabs":{"tienTrinh":[{"chuong":"@c1121","loai":"tái hiện","importance":"major","giaiDoan":"Hạt châu Nghịch Hành Giả dẫn ra một chỉ","text":"Thiên Vận Nhất Chỉ tái hiện dưới dạng ngón tay khổng lồ do ánh sáng bảy màu ngưng tụ, khiến Vương Lâm nhận ra liên hệ với Thiên Vận Tử.","anchor":"Thiên Vận Nhất Chỉ! Nơi đây rõ ràng có liên quan đến Thiên Vận Tử"}]},"capNhatToi":"@c1121","dacDiem":"Ngón tay khổng lồ được kết thành từ ánh sáng bảy màu."},{"id":"than-co-than-cua-vuong-lam","name":"Thân Cổ Thần của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/biến thân","phamCap":"không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Biến thân chiến đấu của Vương Lâm trong trạng thái Cổ Thần khổng lồ.","detail":"Khi bị Thiên Vận Nhất Chỉ và Sinh Tử Cấm truy kích, Vương Lâm hóa thành người khổng lồ hơn ba trăm trượng, mi tâm hiện năm tinh điểm và tinh điểm thứ sáu mơ hồ, dùng lực Cổ Thần phá thế công của tu sĩ Toái Niết trung kỳ.","thuocTinh":"Cổ Thần","uyLuc":"Dùng thân thể khổng lồ và lực Cổ Thần để trực diện đánh tan Thiên Vận Nhất Chỉ.","dacDiem":"Hình thể hơn ba trăm trượng, mi tâm có năm tinh điểm và tinh điểm thứ sáu mơ hồ.","congNang":["Hóa thân Cổ Thần để chiến đấu trực diện với thần thông mạnh @c1122"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1122","tangDatToi":"năm tinh điểm, tinh điểm thứ sáu mơ hồ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1122","loai":"thi triển","importance":"normal","giaiDoan":"Hóa thân Cổ Thần","text":"Vương Lâm hóa thành người khổng lồ hơn ba trăm trượng để phá Thiên Vận Nhất Chỉ.","anchor":"trong nháy mắt, Vương Lâm đã trở thành một người khổng lồ trên ba trăm trượng"}]},"capNhatToi":"@c1122","nguon":["@c1122"]},{"id":"tran-phap-cam-che-trong-son-coc","name":"Trận pháp cấm chế trong sơn cốc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Trận pháp cấm chế được Vương Lâm bố trí sẵn tại sơn cốc để phản kích kẻ truy đuổi.","detail":"Khi lão phụ nhân áo xanh bước vào sơn cốc và kích hoạt cấm chế của mình, Vương Lâm điều khiển ngược thế trận, mở hàng vạn cấm chế bao phủ bà ta, khiến thế truy kích chuyển thành thế bị vây.","thuocTinh":"Cấm chế","uyLuc":"Có thể bao phủ toàn thân lão phụ nhân áo xanh và phối hợp Sinh Tử Cấm, Phá Diệt Cấm tạo thế sinh tử.","dacDiem":"Hàng vạn cấm chế bùng ra trong sơn cốc, có thể bị Vương Lâm điều khiển ngược.","congNang":["Phản vây tu sĩ Toái Niết trung kỳ khi đối phương bước vào khu vực cấm chế @c1122"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1122","tangDatToi":"điều khiển hàng vạn cấm chế","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1122","loai":"thi triển","importance":"normal","giaiDoan":"Phản vây lão phụ nhân","text":"Vương Lâm mở hàng vạn cấm chế trong sơn cốc để bao phủ lão phụ nhân áo xanh.","anchor":"Từng luồng cấm chế bùng ra bao phủ khắp toàn thân lão phụ nhân"}]},"capNhatToi":"@c1122","nguon":["@c1122"]},{"id":"thon-phe-van-vat","name":"Thôn phệ vạn vật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông của Cổ Thần khí","hePhai":"Cổ Thần","soHuu":["Tam Xoa Kích","Vương Lâm"],"blurb":"Thôn phệ vạn vật là thần thông ẩn trong Tam Xoa Kích, chỉ Cổ Thần chân chính mới có thể mở ra. Khi được Vương Lâm kích hoạt, Tam Xoa Kích hóa Hắc Long thôn phệ Sinh Tử Cấm và Tinh Kiếm rồi dung nhập vào thân kích.","detail":"Thôn phệ vạn vật là thần thông của Tam Xoa Kích do Cổ Thần Đồ Ti luyện chế. Thiên Vận Tử từng khiến món vũ khí này phát ra uy lực vốn có nhưng không mở được thần thông, còn Vương Lâm nhờ là Cổ Thần chân chính nên khiến nó bùng phát năng lực thôn phệ, dung nhập thần thông và pháp bảo bị nuốt vào thân kích.","thuocTinh":"thôn phệ","nguonGoc":"Tam Xoa Kích do Cổ Thần Đồ Ti luyện chế","yeuCau":"Cổ Thần chân chính","uyLuc":"Có thể thôn phệ Sinh Tử Cấm và Tinh Kiếm rồi dung nhập vào Tam Xoa Kích.","dacDiem":"Thần thông gắn với bản chất Cổ Thần khí của Tam Xoa Kích, chỉ Cổ Thần chân chính mới mở được.","congNang":["Thôn phệ thần thông và pháp bảo để dung nhập vào Tam Xoa Kích @c1123"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1123","tangDatToi":"kích hoạt được thần thông","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"xuất hiện","importance":"major","giaiDoan":"lộ thần thông","text":"Thôn phệ vạn vật lộ ra là thần thông chỉ Cổ Thần mới mở được trong Tam Xoa Kích. Vương Lâm kích hoạt thần thông này, khiến Tam Xoa Kích hóa Hắc Long thôn phệ Sinh Tử Cấm và Tinh Kiếm.","anchor":"Tam Xoa Kích này vào tay hắn có thể bùng ra thần thông thôn phệ"}]},"trangThai":"đã kích hoạt trong tay Vương Lâm","capNhatToi":"@c1123","nguon":["@c1123"]},{"id":"huyet-nguyen-hoa-anh-de-nhat-tran-linh-hoan-phong-gioi","name":"Huyết Nguyên Hóa Anh, Đệ Nhất Trận Linh Hoán Phong Giới","cn":"","loai":"than-thong","loaiLabel":"Thần thông/trận linh","phamCap":"không rõ","hePhai":"Thương Tùng Tử","soHuu":["Thương Tùng Tử"],"blurb":"Thần thông do Thương Tùng Tử dùng máu và bảy nguyên anh huyễn hóa ký hiệu tia chớp. Chiêu này phá chưởng ấn của Vương Lâm và phóng tia chớp đánh trúng ngực hắn.","detail":"Trong lúc bị Vương Lâm dùng chưởng ấn khổng lồ ép xuống, Thương Tùng Tử thi triển Huyết Nguyên Hóa Anh, Đệ Nhất Trận Linh Hoán Phong Giới. Bảy nguyên anh cùng ký hiệu tia chớp được huyễn hóa để phá chưởng ấn và làm Vương Lâm lần đầu chảy máu Cổ Thần trong trận.","thuocTinh":"huyết nguyên, nguyên anh, trận linh","uyLuc":"Phá được chưởng ấn của Vương Lâm và đả thương thân Cổ Thần.","congNang":["Dùng máu và bảy nguyên anh huyễn hóa ký hiệu tia chớp để phá chưởng ấn và phản kích @c1123"],"nguoiTu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1123","tangDatToi":"thi triển trong chiến đấu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1123","loai":"thi triển","importance":"normal","giaiDoan":"phản kích chưởng ấn","text":"Thương Tùng Tử thi triển Huyết Nguyên Hóa Anh, Đệ Nhất Trận Linh Hoán Phong Giới, dùng bảy nguyên anh và ký hiệu tia chớp phá chưởng ấn của Vương Lâm rồi đánh trúng ngực hắn.","anchor":"Dùng Huyết Nguyên Hóa Anh, Đệ Nhất Trận Linh Hoán Phong Giới"}]},"capNhatToi":"@c1123","nguon":["@c1123"]},{"id":"cuu-huyen-bien","name":"Cửu Huyền Biến","cn":"九玄变","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông phân thân thành chín rồi hợp nhất làm một, khí tức tăng mạnh gấp nhiều lần, gia tăng uy lực tấn công đáng kể.","detail":"Khi thi triển, hình bóng người dùng lập tức hóa thành chín phần, sau đó chín phần hợp lại làm một, khí tức tăng vọt. Vương Lâm dùng thần thông này kết hợp Tam Xoa Kích, giáp Chu Tước và sấm sét để phá nát La Bàn khổng lồ của Thương Tùng Tử.","congNang":["Phân thân thành chín rồi hợp nhất, khí tức tăng mạnh gấp nhiều lần, gia tăng sức tấn công tổng lực"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1124","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1124","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng trong trận phá La Bàn","text":"Vương Lâm thi triển Cửu Huyền Biến phân thân chín rồi hợp nhất, kết hợp toàn bộ lực Cổ Thần trong Tam Xoa Kích, giáp Chu Tước và sấm sét để phá nát La Bàn khổng lồ.","anchor":"hình bóng của hắn lập tức hóa thành chín phần. Nhưng chín phần lại lập tức hợp lại làm một"}]},"nguon":["@c1124"]},{"id":"dao-niem-that-gia","name":"Đạo niệm thật-giả","cn":"","loai":"khac","loaiLabel":"Ý cảnh / Đạo niệm","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo niệm thật-giả là thay đổi lần thứ hai trong đạo niệm của Vương Lâm, được tự chứng ngộ qua việc đối chứng với minh ngộ thiên địa của thú hồn. Nhân đó Vương Lâm tách lọc đạo niệm phù hợp, vứt bỏ phần sai lệch và ngộ ra thật với giả không cần tách biệt hoàn toàn.","detail":"Đạo niệm này thành hình khi Vương Lâm uống ba bình đan dược luyện từ thú hồn, mượn minh ngộ thiên địa của thú hồn làm đối chứng để phân biệt đạo niệm thật và giả của bản thân (@c129). Qua đó ông tách lọc phần đạo niệm phù hợp, vứt bỏ phần sai lệch ra ngoài, và ngộ được rằng thật và giả không cần phải tách biệt hoàn toàn mà nằm xen giữa nhau. Khi đạo niệm bùng ra, nó tạo thành một vòng xoáy hút mọi ý cảnh xung quanh vào để chứng minh, bao phủ hơn phân nửa thế giới bảy màu, mạnh tới mức cả Thương Tùng Tử cũng không thể tiến vào.","thuocTinh":"đạo niệm","nguonGoc":"Vương Lâm tự chứng ngộ qua đối chứng minh ngộ thú hồn","yeuCau":"Uống đan dược chứa minh ngộ thiên địa của thú hồn, có nền tảng đạo niệm trước đó","uyLuc":"Đạo niệm bùng ra bao phủ hơn phân nửa thế giới bảy màu, tạo vòng xoáy hút ý cảnh khiến tu sĩ mạnh như Thương Tùng Tử cũng không thể tiến vào.","dacDiem":"Nằm giữa thật và giả, không tách biệt hoàn toàn, hút ý cảnh người khác vào chứng minh.","trangThai":"hoat-dong","congNang":["Chứng ngộ đạo giữa thật-giả, tách lọc và vứt bỏ đạo niệm sai lệch qua đối chứng minh ngộ thú hồn @c1129","Tạo vòng xoáy hút ý cảnh người khác vào chứng minh, bao phủ phạm vi cực lớn"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1129","tangDatToi":"thay đổi lần thứ hai","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1129","loai":"xuất hiện","importance":"major","giaiDoan":"Chứng ngộ lần đầu","text":"Vương Lâm uống ba bình đan dược luyện từ thú hồn, dùng minh ngộ thiên địa của thú hồn chứng minh thật giả đạo niệm bản thân. Ngộ ra thật và giả không cần phải tách biệt ra hoàn toàn — thay đổi lần thứ hai của đạo niệm. Đạo niệm bùng ra bao phủ hơn phân nửa thế giới bảy màu, hút mọi ý cảnh tạo vòng xoáy.","anchor":"Ý cảnh thật và giả là thay đồi lần thứ hai của đạo niệm Vương Lâm"}]},"capNhatToi":"@c1129","dinhDanh":"goc","nguon":["@c1129"]},{"id":"doi-vi","name":"Đổi vị","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần thông hoán đổi vị trí bản thân với mục tiêu tức thì, thi triển qua Cổ Thần Đại Đỉnh.","detail":"Vương Lâm triệu hồi Cổ Thần Đại Đỉnh, điểm chỉ về phía mục tiêu hoán đổi vị trí hai người tức thì. Lợi dụng khoảnh khắc đối phương kinh hoàng để áp sát tấn công.","congNang":["Hoán đổi vị trí bản thân với mục tiêu tức thì"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1131","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1131","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm triệu hồi Cổ Thần Đại Đỉnh điểm chỉ về phía Thương Tùng Tử, hoán đổi vị trí hai người tức thì để áp sát tấn công.","anchor":"Lời vừa nói ra, thân thể Thương Tùng Tử ở phương xa đột nhiên lóe lên hào quang"}]},"nguon":["@c1131"]},{"id":"dao-niem-ngung-tu","name":"Đạo niệm ngưng tụ","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Ý cảnh ứng dụng","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Triệu hồi tất cả đạo niệm đã vứt bỏ, ngưng tụ thành vòng xoáy phòng thủ hoặc nén thành khối tinh thạch đen có uy lực phá đạo tâm tu sĩ Toái Niết.","detail":"Vương Lâm triệu hồi toàn bộ đạo niệm hỗn tạp đã vứt bỏ trong thế giới bảy màu từ bốn phương tám hướng, ngưng tụ thành vòng xoáy khổng lồ làm phòng thủ khiến lão già Toái Niết hậu kỳ phải ngừng tay. Sau đó nén lại thành khối tinh thạch màu đen, uy lực sánh pháp bảo cực mạnh.","congNang":["Triệu hồi đạo niệm hỗn tạp đã bỏ, ngưng tụ thành vũ khí hoặc phòng thủ","Nén thành khối tinh thạch đen có thể phá đạo tâm tu sĩ Toái Niết"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1131","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1131","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Triệu hồi đạo niệm từ bốn phương tám hướng ngưng tụ thành vòng xoáy phòng thủ trước lão già Toái Niết hậu kỳ, rồi nén thành khối tinh thạch đen.","anchor":"tất cả đạo niệm từ bốn phương tám hướng phóng thẳng về phía Vương Lâm"}]},"nguon":["@c1131"]},{"id":"phuong-phap-tao-dao-tuy","name":"Phương pháp tạo Đạo Tủy","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Phương pháp tạo Đạo Tủy là bí pháp cốt lõi được Vương Lâm giải mã từ ký ức Thương Tùng Tử: dùng Mê Thất giả thôn đạo, Minh Chí giả nuôi đạo, dung nhập vào bia đá, rồi dùng kinh văn trên hài cốt chuyển hóa ép đạo ra khỏi hài cốt hóa thành đạo tủy. Đạo tủy chính là chất lỏng chứa trong bình ngọc.","detail":"Phương pháp được giải mã từ ký ức Thương Tùng Tử, liên quan tới cơ chế bia đá và hài cốt trong thế giới bảy màu (@c1133). Quy trình dùng Mê Thất giả thôn đạo, Minh Chí giả nuôi đạo, dung nhập vào bốn tấm bia đá, rồi dùng kinh văn trên nửa bộ hài cốt dưới bia đá chuyển hóa thành lực lượng ép đạo ra khỏi hài cốt, hóa thành huyết dịch — thực chất là đạo tủy. Uống đạo tủy sẽ có được đạo tâm của chủ nhân hài cốt nhưng phải trả giá bằng việc rơi vào trạng thái ngủ say không biết bao giờ tỉnh.","thuocTinh":"Đạo","nguonGoc":"Giải mã từ ký ức Thương Tùng Tử, liên quan cơ chế bia đá và hài cốt trong thế giới bảy màu","congNang":["Ép đạo từ hài cốt đại năng, chuyển hóa thành đạo tủy thông qua kinh văn khắc trên hài cốt","Uống đạo tủy sẽ đắc đạo tâm của chủ nhân hài cốt, đồng thời rơi vào trạng thái ngủ say vô thời hạn (@c1133)"],"tabs":{"tienTrinh":[{"chuong":"@c1133","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Giải mã bí mật","text":"Vương Lâm giải mã từ ký ức Thương Tùng Tử: chất lỏng trong bình ngọc là đạo tủy, được tạo bằng phương pháp dùng Mê Thất giả thôn đạo, Minh Chí giả nuôi đạo, dung nhập vào bia đá, rồi dùng kinh văn trên hài cốt chuyển hóa.","anchor":"dùng Mê Thất giả thôn đạo, lấy Minh Chí giả nuôi đạo rồi dung nhập vào bốn tấm bia đá nơi đây"}]},"nguon":["@c1133"]},{"id":"thien-dia-thai-son","name":"Thiên Địa Thái Sơn","cn":"天地太初","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực cao (vượt xa Tàn Dạ)","hePhai":"Quy tắc bảy màu","soHuu":["Chưởng Tôn"],"blurb":"Thần thông của Chưởng Tôn, lấy bảy màu làm dẫn, cùng hệ với thần thông Tàn Dạ nhưng tầng cấp vượt xa. Chỉ một chiêu phong ấn bằng hào quang bảy màu đã giết chết cường giả cảnh giới Không Linh Chi.","detail":"Thiên Địa Thái Sơn là thần thông do Chưởng Tôn tu luyện, theo lờião nhân là loại quy tắc lấy bảy màu làm dẫn. Công pháp vận dụng hào quang bảy màu để phong ấn đối thủ với uy lực khủng khiếp. Nó cùng hệ với thần thông Tàn Dạ nhưng tầng cấp vượt xa. Tại @c1134, Chưởng Tôn thi triển thần thông này, chỉ một chiêu phong ấn đã giết chết Chiến Tinh Dã cảnh giới Không Linh Chi.","congNang":["Phong ấn đối thủ bằng hào quang bảy màu @c1134","Một chiêu diệt cường giả cảnh giới Không Linh Chi @c1134"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1134","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1134","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu hé lộ trong ảo cảnh","text":"Chưởng Tôn dùng Thiên Địa Thái Sơn lấy bảy màu làm dẫn, một chiêu phong ấn giết chết Chiến Tinh Dã cảnh giới Không Linh Chi.","anchor":"Thiên địa mở thái, thiên đầu địa cuối, thứ lão phu tu luyện gọi là Thiên Địa Thái"}]},"nguon":["@c1134"],"uyLuc":"Một chiêu phong ấn giết chết Chiến Tinh Dã cảnh giới Không Linh Chi @c1134.","dacDiem":"Lấy bảy màu làm dẫn, cùng hệ với thần thông Tàn Dạ nhưng tầng cấp vượt xa."},{"id":"thien-dao-ke","name":"Thiên Đạo Kế","cn":"天道计","loai":"bi-thuat","loaiLabel":"Bí thuật / Kế sách","phamCap":"","hePhai":"","soHuu":["Chưởng Tôn"],"blurb":"Thiên Đạo Kế là mưu đồ dài hạn của Chưởng Tôn: tặng Chiến Tự Thiếp cho Chiến Tinh Dã tu luyện, sau đó giết lấy chiến hồn làm dẫn để tìm xương cốt Chiến Lão Quỷ Không Kiếp, bức ra đạo tủy của hai sư đồ. Chưởng Tôn gọi đây là Hủy Kỳ Niết bản tôn Thiên Đạo Kế.","detail":"Thiên Đạo Kế là cục diện do Chưởng Tôn bày ra xuyên nhiều đời. Kế sách bắt đầu bằng việc tặng Chiến Tự Thiếp cho Chiến Tinh Dã, đợi hắn tu luyện đạt tới Không Linh Chi rồi ra tay giết hại, lấy chiến hồn làm dẫn để tìm nơi chôn cất thi hài sư phụ hắn là Chiến Lão Quỷ Không Kiếp. Từ hài cốt ấy bức ra đạo tủy của cả hai người sư đồ. Chưởng Tôn công khai tuyên bố mưu kế này vào thời điểm giết Chiến Tinh Dã, gọi nó là Hủy Kỳ Niết bản tôn Thiên Đạo Kế @c1134.","congNang":["Tìm và bức ra đạo tủy Chiến Lão Quỷ thông qua chiến hồn truyền nhân làm dẫn @c134"],"tabs":{"tienTrinh":[{"chuong":"@c1134","loai":"xuất hiện","importance":"major","giaiDoan":"Tiết lộ toàn bộ mưu kế qua ảo cảnh","text":"Chưởng Tôn tuyên bố mưu kế khi giết Chiến Tinh Dã: tặng Chiến Tự Thiếp để tu luyện, giết lấy chiến hồn tìm xương cốt Chiến Lão Quỷ, bức ra đạo tủy.","anchor":"lấy hài cốt của lão bức ra đạo tủy của hai người sư đồ các ngươi, Hủy Kỳ Niết, bản tôn Thiên Đạo Kế"}]},"nguon":["@c1134"]},{"id":"bach-the-huyet-nguyen-hoa-anh","name":"Bách Thế Huyết Nguyên Hóa Anh","cn":"百世血源化婴","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Phong giới","soHuu":["Thương Tùng Tử"],"blurb":"Công pháp tu luyện của Thương Tùng Tử, triệu hồi Đệ Thất Linh của Phong giới, tạo chín nguyên anh mỗi cái tự ngưng tụ thần thông, nâng hiệu quả tu luyện lên chín lần.","detail":"Cảm ngộ từ tượng đá khổng lồ trong sương mù, triệu hồi Đệ Thất Linh của Phong giới. Tạo ra chín vật giống nguyên anh nhưng uy lực vượt xa, mỗi nguyên anh có thể tự ngưng tụ thần thông, cho phép tu luyện đồng thời nhiều thần thông mà bình thường phải lựa chọn. Thương Tùng Tử trước trận với Vương Lâm đã bị lão bà áo xanh lấy mất một nguyên anh.","congNang":["Tạo chín nguyên anh, mỗi cái tự ngưng tụ thần thông","Nâng hiệu quả tu luyện thần thông lên chín lần","Cho phép tu nhiều thần thông đồng thời"],"nguoiTu":[{"ten":"Thương Tùng Tử","tuChuong":"@c1134","tangDatToi":"Chín nguyên anh (mất một do lão bà áo xanh)","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1134","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ qua ký ức Thương Tùng Tử","text":"Vương Lâm từ ký ức Thương Tùng Tử biết được công pháp này triệu hồi Đệ Thất Linh của Phong giới, tạo chín nguyên anh tự ngưng tụ thần thông.","anchor":"công pháp tu luyện của lão chính là thuật Bách Thế Huyết Nguyên Hóa Anh, triệu hồi ra Đệ Thất Linh của Phong giới"}]},"nguon":["@c1134"]},{"id":"tran-phap-tinh-vuc-ao-canh","name":"Trận pháp khổng lồ trong ảo cảnh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp lớn như tinh vực xuất hiện trong ảo cảnh mắt tượng đá, phong tỏa bốn phía giam cầm Luyện Khí Sĩ và Tiên nhân, chứa chín luồng hào quang tàn sát.","detail":"Xuất hiện trong ảo cảnh khi hai mắt tượng đá tổ tiên Thiểm Lôi tộc mở ra. Trận pháp được tiên khí bao phủ, dù bị công kích mạnh mẽ hay tự bạo thân thể cũng không rung chuyển. Bên trong chứa chín luồng hào quang sát thương (gồm Khai Thiên Phủ và tia chớp), giết hại mọi người trên đường đi qua. Bên ngoài trận pháp có vô số người kỳ dị không phải tu sĩ đứng chế giễu khinh thường.","congNang":["Phong tỏa tinh vực, giam cầm và tàn sát Luyện Khí Sĩ cùng Tiên nhân"],"dacDiem":"Chứa chín luồng hào quang sát thương, không thể phá từ bên trong dù dùng mọi cách","nguon":["@c1135"]},{"id":"thiem-loi-bang","name":"Thiểm Lôi Băng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thiểm Lôi tộc","soHuu":["Thanh niên ký hiệu tia chớp"],"blurb":"Chiêu thức của Thiểm Lôi Tộc, ngưng tụ tia chớp bốn phía thành hình bóng hư ảo trăm trượng bao phủ lôi quang.","detail":"Người thi triển ngưng tụ tia chớp khắp bốn phía, tạo thành một hình bóng khổng lồ trăm trượng bao phủ lôi quang. Hình bóng này có thể được tăng cường bằng bí thuật mượn lực tổ tiên. Bị Vương Lâm phá vỡ dễ dàng.","congNang":["Triệu hoán hình ảnh hư ảo trăm trượng từ lôi quang để tấn công"],"nguoiTu":[{"ten":"Thanh niên ký hiệu tia chớp","tuChuong":"@c1137","tangDatToi":"","trangThai":"da-chet"}],"tabs":{"tienTrinh":[{"chuong":"@c1137","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong trận đấu với Vương Lâm","text":"Người Thiểm Lôi Tộc triệu hoán hình bóng hư ảo trăm trượng lôi quang để chiến đấu với Vương Lâm nhưng bị phá vỡ.","anchor":"tia chớp khắp bốn phía lập tức ngưng tụ thành một hình bóng khổng lồ"}]},"nguon":["@c1137"]},{"id":"muon-luc-to-tien-loi-quang","name":"Mượn lực tổ tiên lôi quang","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thiểm Lôi tộc","soHuu":["Thanh niên ký hiệu tia chớp"],"blurb":"Bí thuật cầu cứu cuối cùng của Thiểm Lôi Tộc, mượn lực lượng tổ tiên lôi quang đổ vào hư ảnh biến thành hóa thân thiên lôi.","detail":"Khi sắp chết, tu sĩ Thiểm Lôi Tộc hô khẩu quyết mượn lực lượng tổ tiên lôi quang, sấm sét thiên địa hợp nhất với hư ảnh trăm trượng biến nó thành hóa thân thiên lôi. Bị Vương Lâm phá vỡ bằng một bước Chân Giả ý cảnh.","congNang":["Mượn lực tổ tiên đổ vào hư ảnh, biến thành hóa thân thiên lôi để chiến đấu"],"nguoiTu":[{"ten":"Thanh niên ký hiệu tia chớp","tuChuong":"@c1137","tangDatToi":"","trangThai":"da-chet"}],"tabs":{"tienTrinh":[{"chuong":"@c1137","loai":"thi triển","importance":"normal","giaiDoan":"Chiêu cuối cùng trước khi bị giết","text":"Người Thiểm Lôi Tộc dùng chiêu mượn lực tổ tiên triệu hoán hư ảnh trăm trượng lần hai nhưng bị Vương Lâm đạp tan bằng Chân Giả ý cảnh.","anchor":"Mượn lực lượng tổ tiên lôi quang, giúp ta thôn phệ tu sĩ Phong giới này"}]},"nguon":["@c1137"]},{"id":"trieu-hoan-toc-linh","name":"Triệu hoán Tộc linh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Hỏa Tước Tộc","soHuu":["Thanh niên ký hiệu ngọn lửa"],"blurb":"Bí thuật Hỏa Tước Tộc, hy sinh nguyên thần để triệu hoán Tộc linh — con chim lửa đen khổng lồ.","detail":"Trước khi chết, tu sĩ Hỏa Tước Tộc dùng tư cách tộc nhân thỉnh Tộc linh, hy sinh nguyên thần tan vỡ để triệu hoán con chim lửa đen khổng lồ. Tộc linh bị Chu Tước thật của Vương Lâm thôn phệ hoàn toàn.","congNang":["Hy sinh nguyên thần triệu hoán linh vật bộ tộc để chiến đấu"],"nguoiTu":[{"ten":"Thanh niên ký hiệu ngọn lửa","tuChuong":"@c1137","tangDatToi":"","trangThai":"da-chet"}],"tabs":{"tienTrinh":[{"chuong":"@c1137","loai":"thi triển","importance":"normal","giaiDoan":"Chiêu cuối cùng trước khi chết","text":"Người Hỏa Tước Tộc hy sinh nguyên thần triệu hoán Tộc linh chim lửa đen nhưng Tộc linh bị Chu Tước thật thôn phệ.","anchor":"Dùng tư cách Hỏa Tước tộc, thỉnh Tộc linh"}]},"nguon":["@c1137"]},{"id":"luc-phan-nguyet","name":"Lực Phản Nguyệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Nguyệt Phệ tộc","soHuu":["Thanh niên ký hiệu trăng lưỡi liềm"],"blurb":"Thần thông của Nguyệt Phệ tộc, tạo vầng trăng khuyết trong gió lốc để phản đòn, phản lại công kích về phía đối thủ.","detail":"Khi thi triển, xuất hiện vầng trăng khuyết bên trong gió lốc, phản lại đòn tấn công (kể cả Một quyền Cổ Thần hệ ảo) về phía đối phương. Bị Vương Lâm dùng lực lượng Cổ Thần phá vỡ hoàn toàn.","thuocTinh":"Nguyệt","nguonGoc":"Thần thông của Nguyệt Phệ tộc","congNang":["Tạo vầng trăng khuyết trong gió lốc phản đòn công kích về phía đối thủ"],"nguoiTu":[{"ten":"Thanh niên ký hiệu trăng lưỡi liềm","tuChuong":"@c1138","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1138","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong trận chiến với Vương Lâm","text":"Thanh niên Nguyệt Phệ tộc dùng Lực Phản Nguyệt tạo vầng trăng khuyết phản lại Một quyền Cổ Thần hệ ảo, nhưng bị Vương Lâm phá vỡ hoàn toàn.","anchor":"Một quyền Cổ Thần he ảo từ trong ầm ầm phóng ra rồi lao về phía Vương Lâm"}]},"nguon":["@c1138"]},{"id":"nguyet-cam-than-no","name":"Nguyệt Cấm, thần nộ","cn":"月禁","loai":"bi-thuat","loaiLabel":"Cấm thuật","phamCap":"Cấm thuật cổ xưa nhất Nguyệt Phệ tộc","hePhai":"Nguyệt Phệ tộc","soHuu":["Thanh niên ký hiệu trăng lưỡi liềm"],"blurb":"Cấm thuật cổ xưa nhất của Nguyệt Phệ tộc, xây trên quy ước che chở Thái Cổ của vương tộc Cổ Thần. Khi thi triển, người dùng phải quỳ gối bái lạy để triệu hồi hư ảnh Cổ Thần cao vài trăm trượng, mượn thần hồn lực Cổ Thần tộc dung nhập vào thân thể chiến đấu.","detail":"Nguyệt Cấm, thần nộ là cấm thuật Thái Cổ của Nguyệt Phệ tộc, dựa trên quy ước che chở mà vương tộc Cổ Thần từng hạ lệnh dành cho Nguyệt Phệ tộc. Khi thi triển, người dùng phải quỳ gối bái lạy, triệu hồi hư ảnh Cổ Thần vài trăm trượng xuất hiện phía sau, mượn thần hồn lực Cổ Thần tộc dung nhập vào thân thể. Hư ảnh Cổ Thần có bảy Cổ Thần Tinh Điểm sáng rực trên mi tâm, mở mắt tung quyền tấn công. Cấm thuật chỉ có hiệu lực khi quy ước Thái Cổ còn tồn tại; về sau bị Vương Lâm dùng quyền vương tộc Cổ Thần ra lệnh linh hồn tiêu tán, khiến cấm thuật mất hiệu lực hoàn toàn. Trong truyện, cấm thuật xuất hiện khi một thanh niên Nguyệt Phệ tộc tuyệt vọng sử dụng nó (@c1138).","thuocTinh":"Cổ Thần / Nguyệt","nguonGoc":"Cấm thuật Thái Cổ của Nguyệt Phệ tộc, dựa trên quy ước che chở của vương tộc Cổ Thần","dacDiem":"Cực kỳ khuất nhục — phải quỳ gối bái lạy mới thi triển được, chỉ dùng khi vô cùng nguy cấp; hiệu lực phụ thuộc hoàn toàn vào quy ước Thái Cổ của vương tộc Cổ Thần","congNang":["Triệu hồi hư ảnh Cổ Thần cao vài trăm trượng, mượn thần hồn lực Cổ Thần tộc dung nhập vào thân thể chiến đấu","Hư ảnh Cổ Thần mở mắt, tung quyền tấn công (có bảy Cổ Thần Tinh Điểm sáng rực trên mi tâm)"],"nguoiTu":[{"ten":"Thanh niên ký hiệu trăng lưỡi liềm","tuChuong":"@c1138","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1138","loai":"thi triển","importance":"major","giaiDoan":"Thi triển lần đầu trong trận chiến với Vương Lâm","text":"Thanh niên Nguyệt Phệ tộc tuyệt vọng sử dụng cấm thuật Nguyệt Cấm thần nộ, quỳ gối triệu hồi hư ảnh Cổ Thần mượn thần hồn lực. Bị Vương Lâm dùng quyền vương tộc Cổ Thần ra lệnh linh hồn tiêu tán, cấm thuật mất hiệu lực.","anchor":"Nguyệt Cấm, thần nộ"}]},"nguon":["@c1138"]},{"id":"quy-uoc-thai-co","name":"Quy ước Thái Cổ (Cổ Thần che chở Nguyệt Phệ tộc)","cn":"","loai":"khac","loaiLabel":"Quy ước / Chế ước","phamCap":"Quy ước tộc cổ đại","hePhai":"Cổ Thần tộc / Nguyệt Phệ tộc","soHuu":[],"blurb":"Quy ước Thái Cổ là mệnh lệnh do vương tộc Cổ Thần banra từ thời Thái Cổ, buộc toàn tộc Cổ Thần che chở Nô tộc Nguyệt Phệ, ý chí ấy tồn tại qua muôn đời dù Cổ Thần đã chết. Chỉ khi một vương tộc mới xuất hiện và hạ lệnh vứt bỏ thì quy ước mới bị xóa, và Vương Lâm với tư cách vương tộc Cổ Thần đã chính thức xóa bỏ nó, khiến cấm thuật Nguyệt Cấm mất hiệu lực.","detail":"Năm xưa vương tộc Cổ Thần hạ lệnh cho toàn tộc che chở Nô tộc Nguyệt Phệ, ý chí đó tồn tại qua muôn đời dù Cổ Thần đã chết — linh hồn Cổ Thần trong thiên địa vẫn tự động bảo vệ Nguyệt Phệ tộc và cho phép họ mượn thần hồn lực Cổ Thần qua cấm thuật Nguyệt Cấm. Quy ước chỉ có thể bị xóa khi một vương tộc mới xuất hiện và hạ lệnh vứt bỏ. Tới @c1138, Vương Lâm dùng quyền vương tộc Cổ Thần, ra lệnh bằng ngôn ngữ Cổ Thần cho linh hồn tiêu tán, chính thức xóa bỏ quy ước, khiến cấm thuật Nguyệt Cấm mất hiệu lực và toàn tộc Nguyệt Phệ chấn động.","congNang":["Linh hồn Cổ Thần tồn tại trong thiên địa tự động che chở Nguyệt Phệ tộc","Cho phép Nguyệt Phệ tộc mượn thần hồn lực Cổ Thần qua cấm thuật Nguyệt Cấm","Chỉ vương tộc Cổ Thần mới có thể ra lệnh bằng ngôn ngữ Cổ Thần để xóa bỏ quy ước @c1138"],"tabs":{"tienTrinh":[{"chuong":"@c1138","loai":"nhắc tới","importance":"major","giaiDoan":"Bị Vương Lâm xóa bỏ vĩnh viễn","text":"Vương Lâm dùng quyền vương tộc Cổ Thần ra lệnh bằng ngôn ngữ Cổ Thần cho linh hồn tiêu tán, chính thức xóa bỏ quy ước che chở Nguyệt Phệ tộc từ thời Thái Cổ.","anchor":"Muốn chuyện này chấm dứt thì trừ khi một vương tộc mới xuất hiện rồi hạ lệnh cho bọn họ vứt bỏ ý chí che chở này đi"}]},"trangThai":"Đã bị xóa bỏ bởi Vương Lâm","capNhatToi":"@c1138","nguon":["@c1138"],"dacDiem":"Ý chí quy ước tồn tại qua muôn đời dù Cổ Thần đã chết, chỉ vương tộc Cổ Thần mới có quyền hạ lệnh xóa bỏ."},{"id":"chu-tuoc-thuc-tinh-lan-ba","name":"Chu Tước thức tỉnh lần thứ ba","cn":"朱雀第三次觉醒","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / Huyết mạch giác tỉnh","phamCap":"Cực hiếm, từ viễn cổ trở về trước mới có vài người đạt","hePhai":"Chu Tước","soHuu":["Vương Lâm"],"blurb":"Chu Tước thức tỉnh lần thứ ba là cảnh giới thức tỉnh cực kỳ hiếm của Chu Tước, tồn tại từ thời Thái Cổ và gần như tuyệt diệt khi những kẻ đạt được đã bị diệt sạch từ thời thượng cổ. Người đạt được trở thành linh hồn ngọn lửa thiên địa, nắm thần thông hiệu lệnh tất cả lửa trong thiên địa. Tính tới mốc mới nhất, ngọn lửa đã tiến từ bạch sắc lên lam sắc với uy lực vượt xa trước đó.","detail":"Chu Tước bạch sắc lao vào mắt trái Vương Lâm, ngọn lửa chuyển từ đỏ thẫm sang trắng, mang uy lực hủy thiên diệt địa. Đây là lần thức tỉnh thứ ba của Chu Tước, cực kỳ hiếm từ thời Thái Cổ, những kẻ có được đã bị diệt sạch từ thời thượng cổ nên gần như tuyệt diệt. Người đạt tới cảnh giới này là linh hồn ngọn lửa thiên địa, có thần thông hiệu lệnh mọi ngọn lửa. Tại mốc @c1140, Vương Lâm phong tỏa toàn thân giữ trọn ngọn lửa, khiến lửa đạt đỉnh phong rồi nổ tung, chuyển từ bạch sắc sang lam sắc với uy lực vượt xa bạch sắc.","congNang":["Hiệu lệnh tất cả lửa trong thiên địa","Thiêu đốt mọi vật dưới cấp mười hai, thôn phệ đạo niệm dung nhập vào lửa","Phá hủy cấm chế Tuế Nguyệt cấm","Ngọn lửa chuyển sang lam sắc, uy lực vượt xa bạch sắc @c1140","Có thể đốt cháy nguyên thần và thân thể tu sĩ Toái Niết @c140","Thiêu chết mãnh thú hệ hỏa viên mãn, hồn phách hóa ý niệm dung hợp vào lửa @c1140","Gây cộng hưởng lửa toàn tộc Chu Tước Thánh Tông @c1140"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1139","tangDatToi":"Lam sắc","trangThai":"hoan-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c1139","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Thức tỉnh lần thứ ba","text":"Chu Tước bạch sắc lao vào mắt trái Vương Lâm, ngọn lửa chuyển sang trắng, uy lực hủy thiên diệt địa. Từ viễn cổ đến nay gần như tuyệt diệt, người ba lần thức tỉnh là linh hồn ngọn lửa thiên địa.","anchor":"những kẻ có lần thứ ba thức tỉnh đã hoàn toàn bị diệt sạch từ thời kỳ thượng cổ"},{"chuong":"@c1140","loai":"thi triển","importance":"major","giaiDoan":"Hoàn thành thức tỉnh lần ba","text":"Vương Lâm phong tỏa toàn thân giữ trọn ngọn lửa, lửa đạt đỉnh phong nổ tung chuyển từ bạch sắc sang lam sắc. Chu Tước lam sắc xuất hiện, hoàn thành dục hỏa trọng sinh. Lửa lam quét khắp thế giới bảy màu, phá hủy mọi cấm chế.","anchor":"Chu Tước thức tỉnh lần thứ ba giống như dục hỏa trọng sinh"}]},"capNhatToi":"@c1139","nguon":["@c1139","@c1140"],"uyLuc":"Uy lực hủy thiên diệt địa; khi lửa đạt đỉnh phong nổ tung chuyển sang lam sắc, uy lực vượt xa bạch sắc, đủ đốt cháy nguyên thần và thân thể tu sĩ Toái Niết @c1140","dacDiem":"Ngọn lửa tiến hóa theo sắc độ từ đỏ thẫm sang bạch sắc rồi lam sắc, uy lực tăng theo từng bậc; người đạt được là linh hồn ngọn lửa thiên địa @c1140"},{"id":"phuong-phap-thon-phe-co-than-nguyet-phe-toc","name":"Phương pháp thôn phệ Cổ Thần của Nguyệt Phệ tộc","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Nguyệt Phệ tộc","soHuu":["Nguyệt Phệ tộc"],"blurb":"Bí thuật Nguyệt Phệ tộc nghiên cứu từ thời Thái Cổ, dùng chín pho tượng Cổ Thần cưỡng chế hấp thu lực lượng Cổ Thần nhằm đoạt quyền lợi Cổ Thần.","detail":"Có sơ hở và nguy hiểm lớn, chưa ai hoàn toàn thành công. Nguyệt Phệ tộc kỳ vọng biến Cổ Thần tộc thành nô lệ thông qua phương pháp này.","congNang":["Thôn phệ, hấp thu lực lượng Cổ Thần qua chín pho tượng"],"tabs":{"tienTrinh":[{"chuong":"@c1139","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lộ diện phương pháp","text":"Nguyệt Phệ tộc nghiên cứu từ thời Thái Cổ, dùng chín pho tượng cưỡng chế hấp thu lực lượng Cổ Thần nhưng tồn tại sơ hở lớn, chưa ai thành công hoàn toàn.","anchor":"cuối cùng bọn họ cũng nghiên cứu ra một phương pháp có thể thôn phệ Cổ Thần"}]},"capNhatToi":"@c1139","nguon":["@c1139"]},{"id":"chan-gia-y-canh","name":"Chân Giả ý cảnh","cn":"","loai":"bi-thuat","loaiLabel":"Ý cảnh","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chân Giả ý cảnh là cnh giới lĩnh ngộ màba ý cảnh Hoả, Lôi, Chiến của Vương Lâm đều đã đạt tới. Nếu dung hợp được ba ý cảnh này, tu vi sẽ đại tiến, không còn đối thủ dưới Thiên Nhân Suy Kiếp.","detail":"Vương Lâm xác nhận cả ba ý cảnh Hoả, Lôi, Chiến của mình đều đã thành Chân Giả ý cảnh (@c1141). Điều còn thiếu chỉ là cơ hội để dung hợp ba ý cảnh lại làm một; khi thành công, tu vi sẽ tiến mạnh mẽ, khiến hắn không còn đối thủ dưới Thiên Nhân Suy Kiếp.","congNang":["Ba ý cảnh Hoả, Lôi, Chiến đều đạt mức Chân Giả, chỉ thiếu cơ hội dung hợp (@c1141)","Khi dung hợp ba ý cảnh, tu vi đại tiến, không còn đối thủ dưới Thiên Nhân Suy Kiếp (@c1141)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1141","tangDatToi":"Chân Giả (Hoả, Lôi, Chiến)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1141","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Ba ý cảnh đạt Chân Giả, chờ dung hợp","text":"Vương Lâm xác nhận Hoả, Lôi, Chiến đều đã thành Chân Giả ý cảnh, chỉ thiếu cơ hội dung hợp.","anchor":"Hỏa, Lôi, Chiến đều đã trở thành Chân Giả ý cảnh của ta"}]},"nguon":["@c1141"],"uyLuc":"Sau khi dung hợp ba ý cảnh, không còn đối thủ dưới Thiên Nhân Suy Kiếp.","dacDiem":"Sự hội tụ của ba ý cảnh Hoả, Lôi, Chiến cùng đạt mức Chân Giả, chờơ hội dung hợp."},{"id":"tran-phap-thai-co-tu-toc","name":"Trận pháp thái cổ (máu và ấn ký tứ tộc)","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Tứ Thánh Tông","soHuu":["Tứ Thánh Tông"],"blurb":"Trận pháp thái cổ dùng máu và ấn ký tộc nhân tứ tộc, bố trí tại khe nứt không gian nối Chu Tước tinh để đối phó Cổ Thần sắp thức tỉnh.","detail":"Trận pháp thái cổ đã được bố trí xong tại khe nứt không gian nối Chu Tước tinh, nơi Cổ Thần sắp thức tỉnh. Dùng máu và ấn ký của tộc nhân tứ tộc, theo phân phó của Thanh Long Thánh Hoàng.","congNang":["Đối phó Cổ Thần thức tỉnh tại khe nứt không gian Chu Tước tinh"],"tabs":{"tienTrinh":[{"chuong":"@c1141","loai":"xuất hiện","importance":"normal","giaiDoan":"Đã bố trí xong","text":"Trận pháp đã được bố trí xong tại khe nứt không gian nối Chu Tước tinh, dùng máu và ấn ký tộc nhân tứ tộc.","anchor":"đã dùng máu và ấn ký của tộc nhân tứ tộc để bố trí trận pháp thái cổ"}]},"nguon":["@c1141"]},{"id":"phong-than-thuat","name":"Phong Thần thuật","cn":"封神術","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông thái cổ","hePhai":"Phong Diệt tộc","soHuu":["Lão già tóc trắng (ngọn núi thế giới bảy màu)"],"blurb":"Đại thần thông phong ấn của Phong Diệt tộc thái cổ, có thể phong ấn lực lượng và thần thông của sinh linh, đổi lại hao tổn sinh cơ vĩnh viễn không thể khôi phục.","detail":"Phong Thần thuật là thần thông đòi hỏi huyết mạch Phong Diệt tộc mới thi triển được. Người thi triển điểm chỉ vào mi tâm, mở ra khe hở bùng hắc quang, huyễn hóa thành ký hiệu phức tạp hấp thu sinh cơ bản thân, rồi phóng hắc quang xuyên qua phòng ngự đối phương để phong ấn đồ đằng lên mi tâm mục tiêu. Mỗi lần thi triển hao tổn sinh cơ khổng lồ không thể khôi phục, khiến ngoại hình lão hóa nhanh chóng. Trong truyện, một lão già tóc trắng bộc lộ huyết mạch Phong Diệt tộc đã dùng thuật này phong ấn ngọn lửa Chu Tước của Vương Lâm (@c1142).","thuocTinh":"Phong ấn","nguonGoc":"Phong Diệt tộc thái cổ","uyLuc":"Phong ấn thành công đồ đằng ngọn lửa Chu Tước lam sắc trên mi tâm Vương Lâm, khiến biển lửa lam sắc khắp thiên địa tiêu tán (@c1142).","dacDiem":"Đòi hỏi huyết mạch Phong Diệt tộc, mỗi lần thi triển hao tổn sinh cơ không thể khôi phục, ngoại hình lão hóa nhanh chóng.","congNang":["Phong ấn lực lượng và thần thông của sinh linh","Điểm chỉ mi tâm mở khe hở bùng hắc quang, huyễn hóa ký hiệu phức tạp hấp thu sinh cơ bản thân","Phóng hắc quang xuyên qua phòng ngự thần thông đối phương, phong ấn đồ đằng lên mi tâm mục tiêu"],"nguoiTu":[{"ten":"Lão già tóc trắng (ngọn núi thế giới bảy màu)","tuChuong":"@c1142","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1142","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Lão già tóc trắng bộc lộ huyết mạch Phong Diệt tộc, thi triển Phong Thần thuật phong ấn đồ đằng ngọn lửa Chu Tước trên mi tâm Vương Lâm, đổi lại sinh cơ hao tổn nghiêm trọng.","anchor":"mi tâm vỡ vụn xuất hiện một khe hở, bên trong khe hở bùng ra hắc quang giống như con mắt thứ ba"}]},"nguon":["@c1142"]},{"id":"tan-dao-thuat","name":"Tán Đạo thuật","cn":"散道术","loai":"bi-thuat","loaiLabel":"Đạo thuật cấm","phamCap":"Sánh ngang Cổ Thần/Cổ Ma/Cổ Yêu","hePhai":"Phong Diệt tộc","soHuu":["Lão già tóc trắng (ngọn núi thế giới bảy màu)"],"blurb":"Đạo thuật cấm của Phong Diệt tộc, mượn đạo hồn quy thuận ngưng tụ thành hào quang vàng bao phủ mục tiêu, khiến mọi đạo niệm tu luyện tan biến, Tiên cũng phải sa vào phàm trần. Đây không phải pháp thuật hay thần thông thông thường mà là đạo thuật — loại lực lượng cực hiếm sánh ngang Cổ Thần, Cổ Ma, Cổ Yêu.","detail":"Tán Đạo thuật bắt nguồn từ Phong Diệt tộc, được xếp vào hàng đạo thuật chứ không phải pháp thuật hay thần thông thường — một loại lực lượng cực kỳ hiếm gặp, sánh ngang Cổ Thần, Cổ Ma, Cổ Yêu. Người thi triển cần triệu hồi đạo hồn của những kẻ quy thuận mình làm nhiên liệu, ngưng tụ thành hào quang vàng bao phủ mục tiêu. Bất kỳ ai bị hào quang vàng bao phủ, tất cả đạo niệm từng tu luyện đều tan biến, dù là Tiên cũng phải sa chân về phàm trần. Đại giá của đạo thuật cực lớn: người thi triển phải dốc hết toàn bộ tu vi lẫn tuổi thọ, như lão già tóc trắng dốc cạn cũng chỉ duy trì được ba hơi thở. Trong truyện, lão già tóc trắng từng triệu hồi toàn bộ đạo hồn từ Mê Thất giả, Minh Chí giả và mãnh thú để ngưng tụ hào quang vàng thi triển @c1143.","thuocTinh":"Đạo thuật cấm","nguonGoc":"Phong Diệt tộc","uyLuc":"Xóa sạch đạo niệm tu luyện, đả hạ mục tiêu về phàm trần dù cảnh giới cao đến đâu, sánh ngang Cổ Thần/Cổ Ma/Cổ Yêu.","dacDiem":"Không phải pháp thuật hay thần thông mà là đạo thuật cực hiếm. Đại giá là tiêu hao toàn bộ tuổi thọ và tu vi, cần đạo hồn quy thuận làm nhiên liệu.","congNang":["Xóa sạch mọi đạo niệm tu luyện của mục tiêu bị hào quang vàng bao phủ","Đả hạ mục tiêu về phàm trần dù cảnh giới cao đến đâu, Tiên cũng sa vào phàm trần","Triệu hồi đạo hồn của những kẻ quy thuận làm nhiên liệu, ngưng tụ thành hào quang vàng @c1143"],"nguoiTu":[{"ten":"Lão già tóc trắng (ngọn núi thế giới bảy màu)","tuChuong":"@c1143","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1143","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Lão già tóc trắng triệu hồi toàn bộ đạo hồn từ Mê Thất giả, Minh Chí giả và mãnh thú, ngưng tụ hào quang vàng bao phủ Vương Lâm. Đánh đổi toàn bộ tuổi thọ, chỉ duy trì ba hơi thở.","anchor":"Hễ là người bị bao phủ trong hào quang màu vàng thì tất cả đạo niệm đã từng tu luyện đều phải tan biến"}]},"nguon":["@c1143"]},{"id":"dao-thuat-lao-gia-toc-trang","name":"Đạo thuật (lão già tóc trắng / Phong Diệt tộc)","cn":"","loai":"bi-thuat","loaiLabel":"Đạo thuật","phamCap":"Đạo cảnh","hePhai":"Phong Diệt tộc","soHuu":["Lão già tóc trắng (ngọn núi thế giới bảy màu)"],"blurb":"Đạo thuật do lão già tóc trắng của Phong Diệt tộc cảm ngộ trong đạo cảnh, có khả năng xuyên thấu ý cảnh đối phương và xâm nhập ký ức linh hồn để xóa bỏ bản nguyên. Triết lý cốt lõi cho rằng bản nguyên mỗi người chính là ký ức trong linh hồn, nên xóa bỏ ký ức đồng nghĩa với giết chết kẻ đó.","detail":"Lão già tóc trắng thuộc Phong Diệt tộc cảm ngộ đạo thuật này khi bước vào đạo cảnh. Khi thi triển, hào quang vàng bao phủ thiên địa, có thể xuyên qua Chiến Ý Cảnh và trực tiếp xâm nhập ký ức linh hồn đối phương. Triết lý cốt lõi là bản nguyên của mỗi người chính là ký ức trong linh hồn, do đó xóa bỏ ký ức thì kẻ đó sẽ chết. Đạo thuật thuộc tầng uy lực bất diệt, vượt trên Thuật và Thần thông. Trong tiến trình, lão già dùng đạo thuật này xâm nhập ký ức Vương Lâm với hào quang vàng xuyên qua Chiến Ý Cảnh (@c1144), và ép Vương Lâm sống lại ký ức đau thương, song vấp phải Tiên Nghịch cùng lực lượng của y (@c1145).","congNang":["Xuyên thấu ý cảnh đối phương, hào quang vàng xuyên qua Chiến Ý Cảnh @c1144","Xâm nhập ký ức linh hồn đối phương @c1144","Xóa bỏ bản nguyên (ký ức) để giết đối phương","Ép đối phương sống lại ký ức đau thương @c1145"],"tabs":{"tienTrinh":[{"chuong":"@c1144","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Lão già tóc trắng thi triển đạo thuật xâm nhập ký ức Vương Lâm, hào quang vàng xuyên qua Chiến Ý Cảnh, đưa Vương Lâm vào ảo cảnh bản nguyên. Sinh cơ cả đời lão tiêu tán trong ba hơi thở.","anchor":"đạo thuật lại là một lực lượng thăng hoa, một loại công kích xóa bỏ linh hồn"},{"chuong":"@c1145","loai":"thi triển","importance":"normal","giaiDoan":"Bị phản đòn tan vỡ","text":"Lão già tóc trắng dùng Đạo thuật ép Vương Lâm nhớ lại ký ức đau thương, nhưng khi gặp Tiên Nghịch và lực lượng Cực, Đạo thuật hoàn toàn bại trận, lão trọng thương.","anchor":"Đạo thuật và Cực, Đạo thuật và Thiên Nghịch, lão căn bản không có bất kỳ khả năng gì để chiến thắng"}]},"nguon":["@c1144","@c1145"],"uyLuc":"Thuộc tầng uy lực bất diệt, vượt trên Thuật và Thần thông; hào quang vàng bao phủ thiên địa, xuyên qua Chiến Ý Cảnh xâm nhập thẳng vào ký ức linh hồn.","dacDiem":"Thi triển bằng hào quang vàng bao phủ thiên địa; triết lý cốt lõi lấy ký ức linh hồn làm bản nguyên, xóa ký ức thì đối phương chết."},{"id":"loai-dao","name":"Loại Đạo","cn":"","loai":"khac","loaiLabel":"Cơ chế / hệ thống trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Loại Đạo là một đại trận thượng cổ bao quanh Phong giới phía tây tinh vực, hấp thu đạo niệm của tu sĩ chết trên Phong giới làm dinh dưỡng nuôi bảy cây hoa kết Đạo quả. Trận pháp được xây dựng bằng thuật đại thần thông và hoạt động liên tục từ thượng cổ tới nay.","detail":"Loại Đạo được xây dựng bằng thuật đại thần thông, tồn tại từ thượng cổ. Đây là đại trận bao quanh Phong giới phía tây tinh vực, kết hợp trận pháp tinh vực để hút đạo niệm tu sĩ chết trên Phong giới qua các thời kỳ: thượng cổ hấp thu quy tắc tiên nhân, viễn cổ hấp thu bản nguyên tu sĩ. Trận pháp hoạt động liên tục qua muôn đời nhằm tẩm bổ bảy cây hoa, thúc đẩy chúng kết Đạo quả. Sự tồn tại của nó được tiết lộ khi mô tả vùng tinh không bảy cây hoa @c1146.","congNang":["Hấp thu đạo niệm tu sĩ chết trên Phong giới nuôi bảy cây hoa kết Đạo quả @c1146"],"nguonGoc":"Xây dựng bằng thuật đại thần thông, tồn tại từ thượng cổ","tabs":{"tienTrinh":[{"chuong":"@c1146","loai":"xuất hiện","importance":"major","giaiDoan":"Tiết lộ cơ chế","text":"Được tiết lộ khi mô tả vùng tinh không bảy cây hoa: đại trận bao quanh Phong giới hấp thu đạo niệm tu sĩ chết, chuyển vào tinh vực nuôi bảy cây hoa kết Đạo quả, hoạt động từ thượng cổ.","anchor":"Đây được gọi là Loại đạo"}]},"nguon":["@c1146"]},{"id":"dai-tran-tinh-vuc-bay-cay-hoa","name":"Đại trận tinh vực bảy cây hoa","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đại trận tinh vực bảy cây hoa là một trận pháp khổng lồ quy mô ngang một Liên Minh tinh vực, gồm nhiều tinh vực hợp thành, trung tâm là bảy cây hoa bảy màu. Kết hợp với đại trận Phong giới, nó tạo thành một hệ thống Loại Đạo.","detail":"Đây là vùng tinh không cực kỳ khổng lồ chứa nhiều tinh vực bên trong tạo thành đại trận, quy mô lớn bằng một Liên Minh tinh vực. Trung tâm có bảy cây hoa bảy màu cao khoảng trăm trượng, đóng vai trò nguồn sống cho toàn bộ tinh không. Đại trận kết hợp với đại trận Phong giới phía tây tạo thành hệ thống Loại Đạo, dùng đạo niệm nuôi dưỡng bảy cây hoa. Đại trận lộ diện khi linh hồn Vương Lâm xuyên qua nham thạch tiến vào tinh không (@c1146).","congNang":["Nuôi dưỡng bảy cây hoa bằng đạo niệm, tạo Đạo quả","Nhiều tinh vực hợp thành đại trận với quy mô ngang một Liên Minh tinh vực (@c1146)"],"tabs":{"tienTrinh":[{"chuong":"@c1146","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện","text":"Linh hồn Vương Lâm xuyên qua nham thạch tiến vào tinh không, lộ ra đại trận gồm nhiều tinh vực tạo thành, trung tâm là bảy cây hoa bảy màu.","anchor":"nhiều tinh vực bên trong tạo thành một đại trận kh*ng b*, trận pháp này có thể lớn bằng một Liên Minh tinh vực"}]},"nguon":["@c1146"],"dacDiem":"Trung tâm là bảy cây hoa bảy màu cao khoảng trăm trượng, làm nguồn sống cho toàn bộ tinh không"},{"id":"dai-tran-phong-gioi-phia-tay","name":"Đại trận Phong giới (phía tây)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đại trận vòng quanh Phong giới ở phía tây tinh vực, thu đạo niệm tu sĩ chết trên Phong giới chuyển vào hệ thống nuôi bảy cây hoa.","detail":"Được xây dựng bằng thuật đại thần thông, bao quanh Phong giới. Khi tu sĩ chết trên Phong giới, đạo niệm của họ bị đại trận này hút vào rồi chuyển sang trận pháp tinh vực, làm dinh dưỡng nuôi bảy cây hoa kết Đạo quả.","congNang":["Thu đạo niệm tu sĩ chết trên Phong giới chuyển vào hệ thống nuôi hoa"],"tabs":{"tienTrinh":[{"chuong":"@c1146","loai":"xuất hiện","importance":"normal","giaiDoan":"Tiết lộ chức năng","text":"Được mô tả khi linh hồn Vương Lâm tiến vào tinh không: đại trận bao quanh Phong giới phía tây, thu đạo niệm tu sĩ chết chuyển vào trận pháp tinh vực.","anchor":"Đại trận này và trận pháp tinh vực bên kia làm cho những tu sĩ chết đi trong Phong giới, tất cả đạo niệm của họ bị bút vào trong trận pháp"}]},"nguon":["@c1146"]},{"id":"bi-thuat-con-hu","name":"Bí thuật Côn Hư","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Côn Hư","soHuu":["Mộc Băng Mi"],"blurb":"Bí thuật của Côn Hư, có khả năng phá vỡ ranh giới tinh vực.","detail":"Mộc Băng Mi dùng bí thuật Côn Hư phá ranh giới chạy đến Man Hoang đại lục trên Vân Hải tinh vực sau khi bị Thác Sâm đánh trọng thương.","congNang":["Phá vỡ ranh giới tinh vực để di chuyển sang nơi khác"],"nguoiTu":[{"ten":"Mộc Băng Mi","tuChuong":"@c1147","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1147","loai":"thi-triển","importance":"normal","giaiDoan":"Mộc Băng Mi sử dụng","text":"Nguyên thần Mộc Băng Mi dùng bí thuật Côn Hư phá vỡ ranh giới tinh vực để chạy đến Man Hoang đại lục.","anchor":"nguyên thần Mộc Băng Mi dùng bí thuật Côn Hư phá vỡ ranh giới"}]},"nguon":["@c1147"]},{"id":"phong-gioi-dai-tran","name":"Phong Giới đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Phong Giới đại trận là trận pháp khổng lồ nằm ở vùng hư vô ngoài Tứ Đại giới, phong tỏa ngăn cách Ngoại Giới (Nội giới) và Thái Cổ Tinh Thần. Khi bị tấn công đến mức nhất định, trận sẽ kích hoạt Trận linh tự động phản kích. Tính tới hiện tại, Thác Sâm thuộc vương tộc Cổ Thần từng đánh hai quyền chỉ làm trận run rẩy mà không phá vỡ nổi @c1148. (+) Đại trận dạng mạng lưới vô biên bao vây thiên địa giới nội, ngăn cản hết thảy sinh linh phá vỡ ra giới ngoại. Từ cổ chí kim chưa ai mượn thiên kiếp phá được — Vương Lâm là người đầu tiên. [CAN-SOAT-GOP] (+) Trận pháp khổng lồ phong tỏa toàn bộ giới nội, tồn tại từ mấy vạn năm, ngăn cách giới nội với Thái Cổ Tinh Thần bên ngoài. [CAN-SOAT-GOP] (+) Đại trận ngăn cách giới nội và giới ngoại từ xưa đến nay, ngăn chặn qua lại giữa hai giới. [CAN-SOAT-GOP]","detail":"Phong Giới đại trận là trận pháp quy mô vô hạn, mơ hồ lộ ánh sáng bảy màu, nằm ở vùng hư vô giữa Tứ Đại giới và Thái Cổ Tinh Thần, giữ vai trò phong tỏa ngăn cách Ngoại Giới (Nội giới) với Thái Cổ Tinh Thần. Có người chủ trận canh giữ ở phía Thái Cổ Tinh Thần. Khi bị tấn công đến mức nhất định, trận kích hoạt Trận linh tự động phản kích, ngưng tụ ra vũ khí gồm trường thương trắng bùng sét và đoản kiếm lam mang kiếm khí cùng khí tức âm hàn để tấn công kẻ xâm phạm. Trường thương nếu bị phá vỡ sẽ ngưng tụ lại mạnh hơn nhiều lần, kèm theo lưới điện khóa chặt mục tiêu. Trận xuất hiện khi Thác Sâm tìm thấy nó ở vùng hư vô ngoài Tứ Đại giới, đánh hai quyền không phá nổi mà chỉ làm trận run rẩy, lần đầu còn bị phản lực đánh bật lui @c1148.","congNang":["Phong tỏa ngăn cách Ngoại Giới (Nội giới) và Thái Cổ Tinh Thần @c1148","Kích hoạt Trận linh tự động phản kích khi bị tấn công đến mức nhất định, ngưng tụ ra trường thương trắng bùng sét và đoản kiếm lam mang kiếm khí cùng khí tức âm hàn @c1148","Trường thương bị phá vỡ sẽ ngưng tụ lại mạnh hơn nhiều lần, tạo lưới điện khóa chặt mục tiêu @c1148"],"tabs":{"tienTrinh":[{"chuong":"@c1148","loai":"xuất hiện","importance":"major","giaiDoan":"Thác Sâm tấn công trận pháp","text":"Thác Sâm tìm thấy Phong Giới đại trận ở vùng hư vô ngoài Tứ Đại giới, đánh hai quyền không phá nổi. Trận linh kích hoạt phản kích bằng trường thương sét và đoản kiếm lam, khóa chặt Thác Sâm bằng lưới điện.","anchor":"phá vỡ trận pháp này thì có thể tiến ra khỏi Ngoại Giới rồi đi vào Thái Cổ Tinh Thần"}]},"nguon":["@c1148","@c1231","@c1418","@c1525"],"uyLuc":"Chống chịu được hai quyền của Thác Sâm thuộc vương tộc Cổ Thần, chỉ run rẩy mà không bị phá vỡ, đồng thời phản lực đánh bật lui người tấn công @c1148.","dacDiem":"Trận pháp quy mô vô hạn, mơ hồ lộ ánh sáng bảy màu, nằm ở vùng hư vô giữa Tứ Đại giới và Thái Cổ Tinh Thần, có người chủ trận canh giữ ở phía Thái Cổ Tinh Thần."},{"id":"tran-phap-phong-gioi-noi-gioi","name":"Trận pháp Phong giới Nội giới","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng cổ đại trận","hePhai":"Cổ Thần tộc","soHuu":[],"blurb":"Trận pháp Phong giới Nội giới là đại trận phong tỏa toàn bộ tu sĩ Nội giới và trói buộc bộ tộc Cổ Thần của Thác Sâm, có tổng cộng Cửu Linh khí linh phòng ngự. Từ xưa đến nay chưa từng bị phá cho đến khi Thác Sâm liều mạng tạo ra khe nứt đầu tiên xông ra ngoài.","detail":"Trận pháp phong tỏa tu sĩ Nội giới, đồng thời trói buộc toàn bộ bộ tộc Cổ Thần. Cốt lõi phòng ngự là Cửu Linh — chín khí linh: đoản kiếm lam sắc, kim đao khổng lồ, Lưu Tinh Chùy (Ngũ Linh), xe bắn đá khổng lồ phóng hỏa cầu (Lục Linh), nha bổng hắc khí hấp thu tâm thần (Thất Linh) và búa khổng lồ Phụ Tổ Vương Khí (Bát Linh), trong đó linh thứ chín chưa lộ diện. Khi Thác Sâm đâm vào, trận pháp lần lượt kích hoạt các khí linh từ Ngũ Linh đến Bát Linh để chống trả (@c1149). Va chạm khiến Tứ Đại Tiên giới khiếp sợ. Thác Sâm phải thi triển Mặc Lưu Phân Thần Thuật và cho nổ tung lưu tinh mới lần đầu tiên tạo ra khe nứt trên trận pháp vốn bất khả phá này.","nguon":["@c1149"],"congNang":["Phong tỏa Nội giới, trói buộc bộ tộc Cổ Thần","Cửu Linh — chín khí linh tự động kích hoạt tấn công kẻ xâm nhập hoặc kẻ muốn thoát ra, lần lượt từ Ngũ Linh đến Bát Linh @c1149","Va chạm với trận pháp khiến Tứ Đại Tiên giới khiếp sợ"],"tabs":{"tienTrinh":[{"chuong":"@c1149","loai":"xuất hiện","importance":"major","giaiDoan":"Lần lượt kích hoạt Ngũ Linh đến Bát Linh, lần đầu bị phá","text":"Trận pháp lần lượt kích hoạt từ Ngũ Linh đến Bát Linh chống Thác Sâm. Bát Linh là búa Phụ Tổ Vương Khí — vũ khí Cổ Thần. Thác Sâm thi triển Mặc Lưu Phân Thần Thuật rồi cho nổ lưu tinh, lần đầu tiên tạo khe nứt trên trận pháp từ xưa chưa ai phá được, xông ra ngoài thành công.","anchor":"Khoảnh khắc này trận pháp từ xưa đến nay chưa từng bị phá lại run rẩy dữ dội giống như muốn tan vỡ"}]},"uyLuc":"Từ xưa đến nay chưa từng bị phá; va chạm với trận pháp khiến Tứ Đại Tiên giới khiếp sợ.","dacDiem":"Có tổng cộng Cửu Linh — chín khí linh phòng ngự, trong đó linh thứ chín chưa lộ diện; các khí linh gồm đoản kiếm lam sắc, kim đao khổng lồ, Lưu Tinh Chùy, xe bắn đá phóng hỏa cầu, nha bổng hắc khí hấp thu tâm thần và búa Phụ Tổ Vương Khí."},{"id":"dao-rieng-vuong-lam","name":"Đạo riêng của Vương Lâm","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo riêng của Vương Lâm là quy tắc mới chưa từng xuất hiện trong thiên địa, hình thành khi sáu yếu tố lôi, hỏa, chiến cùng thật giả, sinh tử, nhân quả dung hợp bên trong Đạo quả cây hoa đỏ thẫm, lấy Thiên Nghịch làm trung tâm.","detail":"Đạo riêng này bắt nguồn từ việc Vương Lâm hấp thu đạo niệm từ Đạo quả cây hoa đỏ thẫm. Trong quá trình đó, sáu yếu tố dung hợp lại thành một luồng lực lượng mới: lôi đạo là quy tắc trừng phạt vạn sinh linh, hỏa đạo là quy tắc dung luyện thiên địa, chiến đạo là quy tắc bất khuất thiên địa, cùng với thật giả, sinh tử và nhân quả. Thiên Nghịch giữ vai trò trung tâm của cả quá trình dung hợp. Cảm ngộ có nguồn gốc từ Đạo quả luân hồi, chưa hoàn toàn chuyển hóa thành của riêng Vương Lâm mà cần thời gian mới thành tựu.","thuocTinh":"Lôi, Hỏa, Chiến, Thật Giả, Sinh Tử, Nhân Quả","nguonGoc":"Dung hợp đạo niệm Đạo quả hoa bảy màu + Thiên Nghịch làm trung tâm","congNang":["Bao hàm sáu yếu tố lôi - hỏa - chiến cùng sinh tử - nhân quả - thật giả dung hợp thành một đạo duy nhất @c1150"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1150","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1150","loai":"xuất hiện","importance":"major","giaiDoan":"Hình thành lần đầu","text":"Sáu yếu tố lôi, hỏa, chiến, thật giả, sinh tử, nhân quả dung hợp trong Đạo quả cây hoa đỏ thẫm với Thiên Nghịch làm trung tâm, tạo thành quy tắc mới chưa từng có trong thiên địa — đạo riêng của Vương Lâm.","anchor":"đã trở thành một luồng lực lượng chưa bao giờ xuất hiện trong thiên địa, một loại quy tắc mới"}]},"nguon":["@c1150"],"dacDiem":"Quy tắc mới chưa từng xuất hiện trong thiên địa, do sáu yếu tố dung hợp lại thành, lấy Thiên Nghịch làm trung tâm."},{"id":"chan-gia-dao-thai-cuc-y-canh","name":"Chân Giả Đạo / Thái Cực Ý Cảnh","cn":"","aliases":["Thái Cực Ý Cảnh"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh mới xuất hiện dưới hình thức huyễn hóa thái cực: một nửa thật một nửa giả, một nửa người một nửa quả, một nửa sống một nửa chết. Hấp thu lôi, hỏa, chiến thành vòng xoáy thái cực với Thiên Nghịch là trung tâm.","detail":"Trong quá trình Đạo quả dung hợp, Chân Giả Đạo huyễn hóa ra dưới dạng thái cực — một nửa thật một nửa giả, một nửa người một nửa quả, một nửa sống một nửa chết. Hấp thu toàn bộ ngọn lửa, tia chớp, Chiến Ý Cảnh tạo thành vòng xoáy thái cực xoay quanh Thiên Nghịch, là cơ chế dung hợp mọi yếu tố tạo nên đạo riêng của Vương Lâm.","congNang":["Hấp thu và dung hợp lôi, hỏa, chiến thành vòng xoáy thái cực với Thiên Nghịch là trung tâm"],"tabs":{"tienTrinh":[{"chuong":"@c1150","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện lần đầu trong Đạo quả","text":"Huyễn hóa ra trong Đạo quả dưới dạng thái cực, hấp thu lôi-hỏa-chiến tạo vòng xoáy quanh Thiên Nghịch.","anchor":"nó là hình thức huyễn hóa của thái cực có một nửa thật và một nửa là giả, một nửa là người, một nửa là quả"}]},"nguon":["@c1150"]},{"id":"quy-tac-moi-chien","name":"Quy tắc mới Chiến","cn":"战","loai":"than-thong","loaiLabel":"Thần thông / Quy tắc","phamCap":"Không rõ","hePhai":"Đạo riêng Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Quy tắc mới Chiến là một quy tắc chưa từng xuất hiện trong trời đất, do lửa mắt trái và thiểm điện mắt phải của Vương Lâm dung hợp mà thành, ẩn chứa chữ Chiến. Khi hình thành, nó rơi vào mi tâm và thu nhỏ thành tinh điểm giống Cổ Thần Chi Tinh.","detail":"Quy tắc mới Chiến hình thành khi lửa mắt trái và thiểm điện mắt phải của Vương Lâm hóa thành hai dấu ấn rồi dung hợp làm một, ẩn chứa chữ Chiến (@c1151). Sau khi rơi vào mi tâm và hợp nhất với đạo thật giả, nó xuất hiện dưới hình thái cực xoay tròn rồi thu nhỏ thành tinh điểm giống Cổ Thần Chi Tinh. Nếu cộng thêm Cửu Tinh Cổ Thần trên mi tâm thì rất dễ bị tưởng lầm là Thập Tinh Cổ Thần. Mỗi khi tinh điểm lóe lên sẽ khiến chiến ý bao phủ toàn thân,uy nhiên Vương Lâm khi ấy vẫn chưa hoàn toàn hiểu và khống chế được quy tắc này.","thuocTinh":"Đạo thật giả + lửa + thiểm điện","nguonGoc":"Do ý cảnh chuyển hóa mà thành, quy tắc mới chưa từng xuất hiện trong trời đất","dacDiem":"Hình thành tinh điểm trên mi tâm giống Cổ Thần Chi Tinh, thỉnh thoảng lóe lên tạo chiến ý bao phủ; dễ bị tưởng lầm là Thập Tinh Cổ Thần khi cộng với Cửu Tinh Cổ Thần.","trangThai":"Mới hình thành, chưa hoàn toàn khống chế","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1151","tangDatToi":"Mới hình thành","trangThai":"dang-tu"}],"congNang":["Hóa thành tinh điểm trên mi tâm giống Cổ Thần Chi Tinh @c1151","Tạo chiến ý bao phủ toàn thân khi tinh điểm lóe lên @c1151"],"tabs":{"tienTrinh":[{"chuong":"@c1151","loai":"xuất hiện","importance":"major","giaiDoan":"Hình thành","text":"Lửa mắt trái và thiểm điện mắt phải hóa hai dấu ấn dung hợp thành quy tắc mới chứa chữ Chiến, rơi vào mi tâm hợp nhất với đạo thật giả, thu nhỏ thành tinh điểm giống Cổ Thần Chi Tinh.","anchor":"Đây là một dấu ấn chưa từng xuất hiện trong trời đất, là một đạo quy tắc mới"}]},"capNhatToi":"@c1151","nguon":["@c1151"]},{"id":"an-ky-no-dich","name":"Ấn ký nô dịch","cn":"","aliases":["Ấn ký thao túng sinh tử"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn ký nô dịch là ấn ký quỷ dị do Vương Lâm phóng ra, rơi vào mi tâm đối phương và dung hợp với ngọn lửa lam, lôi đình cùng chiến ý đã xâm nhập nguyên thần. Đây không phải thủ đoạn giết người mà là để thao túng sinh tử của đối phương — sống làm nô bộc, chết làm ma.","detail":"Ấn ký được Vương Lâm phóng ra từ tay phải, bay chậm rãi tới mi tâm Vân Hồn Tử. Tại đó ấn ký dung hợp với ngọn lửa lam, lôi đình cùng chiến ý vốn đã xâm nhập nguyên thần Vân Hồn Tử, rồi ngưng tụ tại mi tâm và biến mất. Bản chất của ấn ký không nhằm lấy mạng đối phương mà nhằm nắm giữ trọn vẹn sinh tử của họ: khi còn sống thì phải làm nô bộc, khi chết đi thì hóa thành ma phục dịch (@c1152).","congNang":["Thao túng sinh tử đối phương — sống làm nô bộc, chết làm ma (@c152)","Dung hợp với ngọn lửa lam, lôi đình và chiến ý đã xâm nhập nguyên thần để ngưng tụ tại mi tâm đối phương (@c1152)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1152","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1152","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm phóng ấn ký quỷ dị vào mi tâm Vân Hồn Tử, dung hợp với lửa lam, lôi đình, chiến ý, thao túng sinh tử thu Vân Hồn Tử làm nô bộc.","anchor":"không phải là một ấn ký giết người, mà là để thao túng sinh tử"}]},"nguon":["@c1152"],"dacDiem":"Ấn ký quỷ dị được phóng vào mi tâm đối phương, không nhằm giết người mà để khống chế trọn vẹn sinh tử."},{"id":"sat-luc-kiem","name":"Sát Lục Kiếm","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sát Lục Kiếm là chiêu thức Vương Lâm ngưng tụ toàn bộ Sát Lục Khí thành một thanh kiếm đỏ như máu, đâm xuyên mục tiêu rồi vỡ vụn để Sát Lục Khí tràn vào bên trong cơ thể đối phương.","detail":"Sát Lục Kiếm xuất hiện khi Vương Lâm giải phóng toàn bộ Sát Lục Khí đã tích tụ, ngưng kết luồng khí ấy thành hình một thanh kiếm màu đỏ như máu. Thanh kiếm đâm vào ngón tay út của mục tiêu, sau khi xuyên trúng liền vỡ vụn, khiến Sát Lục Khí tràn ngập vào bên trong cơ thể đối phương @c1155.","nguon":["@c1155"],"congNang":["Ngưng tụ toàn bộ Sát Lục Khí thành một thanh kiếm đỏ như máu @c1155","Đâm xuyên mục tiêu rồi vỡ vụn, truyền Sát Lục Khí tràn vào bên trong cơ thể đối phương @c1155"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1155","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1155","loai":"thi triển","importance":"normal","giaiDoan":"Ngưng tụ toàn bộ Sát Lục Khí tấn công ngón tay út","text":"Vương Lâm giải phóng toàn bộ Sát Lục Khí ngưng tụ thành Sát Lục Kiếm đỏ như máu đâm vào ngón tay út, kiếm vỡ vụn và Sát Lục Khí tràn vào bên trong.","anchor":"ngưng tụ hóa thành một thanh Sát Lục Kiếm màu đỏ như máu"}]},"dacDiem":"Kiếm màu đỏ như máu, sau khi đâm trúng mục tiêu thì vỡ vụn để Sát Lục Khí tràn vào bên trong @c1155"},{"id":"quy-tac-moi-cua-vuong-lam","name":"Quy tắc mới của Vương Lâm","cn":"","loai":"khac","loaiLabel":"Quy tắc","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Quy tắc mới của Vương Lâm là quy tắc duy nhất chỉ thuộc về riêng y, hình thành từ sự dung hợp lôi hỏa, sức mạnh đạo quả phong ấn và chiến ý cảnh. Quy tắc này tạo gợn sóng vặn vẹo như tuế nguyệt trùng điệp bao phủ mục tiêu, đủ sức phá hủy ngón tay bàn tay ngoại giới chưởng tôn.","detail":"Quy tắc này được Vương Lâm tự lĩnh ngộ trong trận chiến sinh tử tại Thất Thải giới. Khi bị ngón giữa bàn tay ngoại giới đè xuống, sức mạnh đạo quả mà y hấp thu và phong ấn trước đây bùng phát, dung hợp cùng lôi hỏa và chiến ý cảnh để hình thành một quy tắc hoàn toàn mới chỉ thuộc về duy nhất mình y (@c1156). Quy tắc tạo ra gợn sóng vặn vẹo như tuế nguyệt trùng điệp bao phủ mục tiêu, đủ sức ngược dòng nâng ngón giữa lên và phá hủy hoàn toàn.","thuocTinh":"Lôi hỏa + Đạo quả + Chiến ý cảnh","nguonGoc":"Vương Lâm tự lĩnh ngộ trong trận chiến sinh tử tại Thất Thải giới","uyLuc":"Đủ sức phá hủy ngón tay bàn tay ngoại giới chưởng tôn","dacDiem":"Quy tắc duy nhất chỉ thuộc về Vương Lâm, tạo gợn sóng vặn vẹo như tuế nguyệt trùng điệp","congNang":["Dung hợp lôi hỏa, sức mạnh đạo quả phong ấn và chiến ý cảnh, lĩnh ngộ quy tắc mới chỉ thuộc về duy nhất Vương Lâm @c1156","Tạo gợn sóng vặn vẹo như tuế nguyệt trùng điệp bao phủ mục tiêu để phá hủy @c1156"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1156","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1156","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu hình thành","text":"Vương Lâm dung hợp lôi hỏa, sức mạnh đạo quả phong ấn và chiến ý cảnh, lĩnh ngộ quy tắc mới chỉ thuộc về duy nhất mình hắn, phá hủy hoàn toàn ngón giữa bàn tay ngoại giới.","anchor":"hình thành một quy tắc mới. Trong trời đất này, quy tắc này chỉ thuộc về duy nhất Vương Lâm"}]},"nguon":["@c1156"]},{"id":"dai-tran-phong-toa-that-giai","name":"Đại trận phong tỏa thất giai tinh vực","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Đại trận phong tỏa thất giai tinh vực là trận pháp hình tròn bao bọc tinh vực thất giai ở trạng thái nửa phong tỏa, cần ngọc giản thông hành mới có thể đi qua. Trận có nhiều tu sĩ trông coi.","detail":"Đại trận hình tròn bao bọc tinh vực thất giai, đặt ở trạng thái nửa phong tỏa nhằm ngăn cản ngoại nhân xâm nhập; muốn đi qua phải cóngọc giản thông hành. Trận do nhiều tu sĩ trông coi. Trong tiến trình, đại trận bị Vương Lâm tăng tốc lao thẳng vào phá tan, nứt vỡ như mạng nhện rồi sụp đổ hoàn toàn @c1160.","congNang":["Ngăn cản ngoại nhân bước vào thất giai tinh vực, cần ngọc giản thông hành mới được đi qua"],"tabs":{"tienTrinh":[{"chuong":"@c1160","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phá hủy","text":"Bị Vương Lâm tăng tốc lao thẳng vào phá tan hoàn toàn, nứt vỡ như mạng nhện rồi sụp đổ. Các tu sĩ trông coi trợn mắt há mồm không dám thốt một câu.","anchor":"đại trận xuất hiện vô số khe nứt, với tốc độ cực nhanh lan ra, đảo mắt một cái đã thành dàng như mạng nhện, cuối cùng ầm ầm sụp đổ"}]},"nguon":["@c1160"],"dacDiem":"Trận pháp hình tròn bao bọc tinh vực ở trạng thái nửa phong tỏa, có nhiều tu sĩ trông coi."},{"id":"quy-tac-lua-chu-tuoc-thuc-tinh-lan-ba","name":"Quy tắc lửa — Chu tước thức tỉnh lần ba","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Quy tắc","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Quy tắc lửa hình thành khi Chu tước của Vương Lâm thức tỉnh lần thứ ba, hóa lửa dung nhập vào quy tắc thiên địa để trở thành một quy tắc mới. Trong phạm vi quy tắc này, mọi hỏa thần thông đối phương thi triển đều vô dụng trừ phi vượt khỏi phạm vi thiên địa.","detail":"Chu tước của Vương Lâm thức tỉnh lần ba, hóa thành lửa dung nhập vào quy tắc thiên địa và trở thành quy tắc mới. Trong phạm vi quy tắc, toàn bộ hỏa thần thông đều bị Vương Lâm khống chế, biển lửa của địch có thể bị quay ngược thiêu chết chính chúng. Lửa lam thẫm được ngưng tụ thành hình chu tước lam khổng lồ tham chiến. Tới mốc @c1162, Vương Lâm kích hoạt quy tắc lửa chỉ bằng một chỉ, triệu biển lửa lam thẫm ngưng tụ và diệt nhiều rết cấp 12.","congNang":["Khống chế và hủy mọi ngọn lửa trong phạm vi quy tắc thiên địa","Quay ngược biển lửa của đối phương thiêu chết chính chúng","Ngưng tụ lửa lam thẫm thành chu tước lam khổng lồ chiến đấu","Kích hoạt quy tắc lửa chỉ bằng một chỉ, triệu biển lửa lam thẫm ngưng tụ diệt nhiều rết cấp 12 @c1162"],"tabs":{"tienTrinh":[{"chuong":"@c1162","loai":"thi triển","importance":"major","giaiDoan":"Khai phá quy tắc lửa lần đầu trên chiến trường","text":"Vương Lâm kích hoạt quy tắc lửa diệt nhiều rết cấp 12 chỉ bằng một chỉ, triệu biển lửa lam thẫm ngưng tụ thành chu tước lam đại chiến rết lam ba trăm trượng, nổ nửa thân rết.","anchor":"toàn bộ những người sử dụng hỏa thần thông ở trước mặt Vương Lâm không thể có một chút đất dụng võ"}]},"nguon":["@c1162"],"uyLuc":"Chỉ bằng một chỉ kích hoạt quy tắc lửa đã diệt nhiều rết cấp 12, uy lực đủ nổ nửa thân rết lam cấp 12 @c1162","dacDiem":"Hình thành từ lần thức tỉnh thứ ba của Chu tước, hóa lửa dung nhập quy tắc thiên địa; biểu hiện bằng lửa lam thẫm ngưng tụ thành hình chu tước lam khổng lồ."},{"id":"than-thong-tach-long","name":"Thần thông tách lông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Văn Thú","soHuu":["Văn Thú màu trắng","Văn Thú"],"blurb":"Thần thông bản năng của Văn Thú cấp cao, dựng lông rồi tách lông khỏi thân bắn ra như phi kiếm mang theo sức mạnh phá thiên địa.","detail":"Văn Thú màu trắng dựng lông trên toàn thân, lông mọc dài ra rồi tách khỏi cơ thể bắn ra như đạn tấn công diện rộng, mang theo thần thông phá trời đất. Văn Thú Vương (Vương Lâm) quan sát rồi học theo, cũng tách lông phóng ra đối công.","congNang":["Tách lông khỏi thân bắn ra như phi kiếm tấn công diện rộng"],"nguon":["@c1168"],"tabs":{"tienTrinh":[{"chuong":"@c1168","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Văn Thú màu trắng thi triển thần thông tách lông trong chiến đấu với Văn Thú Vương. Văn Thú Vương quan sát rồi học theo, cũng tách lông phóng ra đối công.","anchor":"lông trên thân thể chợt lay động, trong thời gian ngắn mọc dài ra, khiến cho Văn Thú màu trắng này thoạt nhìn giống như toàn thân lông dài"}]}},{"id":"quy-tac-thu","name":"Quy tắc thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Quy tắc thủ là thủ ấn tổ hợp bốn dấu ấn quy tắc chi tinh trên bốn ngón tay trái, hợp nhất thành một đòn uy lực kinh thiên. Vương Lâm lần đầu thi triển đã trọng thương Toái Niết trung kỳ chỉ trong ba hơi thở.","detail":"Quy tắc thủ được Vương Lâm thi triển lần đầu tại @c1169. Ông liên tục điểm bốn chỉ lên lưng bàn tay trái, mỗi chỉ ngưng tụ sức mạnh thiên địa và tiên lực để tạo ra một dấu ấn quy tắc chi tinh trên một ngón tay (trỏ, giữa, vô danh, út). Bốn dấu ấn hợp thành quy tắc thủ, in thủ ấn lên mi tâm đối phương khiến xúc tu nứt ra, máu phun. Toàn bộ quá trình chỉ mất ba hơi thở.","congNang":["Điểm liên tục bốn chỉ tạo bốn dấu ấn quy tắc chi tinh trên bốn ngón tay trái (trỏ, giữa, vô danh, út) @c1169","Bốn dấu ấn quy tắc chi tinh hợp nhất thành thủ ấn cực mạnh, in lên đối phương gây trọng thương nội ngoại","In thủ ấn lên mi tâm đối phương khiến xúc tu nứt ra, máu phun"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1169","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1169","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm lần đầu thi triển quy tắc thủ, liên tục điểm bốn chỉ tạo bốn dấu ấn quy tắc chi tinh trên bốn ngón tay trái, hợp thành thủ ấn in lên mi tâm Văn Thú Vương màu tím Toái Niết trung kỳ, trọng thương nặng trong ba hơi thở.","anchor":"bốn ngón tay trên tay trái của Vương Lâm đều ẩn chứa dấu ấn quy tắc, dường như trở thành quy tắc thủ"}]},"nguon":["@c1169"],"uyLuc":"Trọng thương Toái Niết trung kỳ trong ba hơi thở, khiến xúc tu đối phương nứt ra và máu phun.","dacDiem":"Tổ hợp bốn dấu ấn quy tắc chi tinh trên bốn ngón tay trái, mỗi dấu ấn ngưng tụ từ sức mạnh thiên địa và tiên lực, hoàn thành chỉ trong ba hơi thở."}]};
